import type { Drill } from "./types";

// Agriculture / senior drills, keyed by module slug — 25 per module.
// Farm owner-operator / agribusiness leader / co-op president: banks, buyers,
// landlords, regulators, family succession, the co-op membership. Merged into course.ts.
export const AGRICULTURE_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-agri-senior-01","level":"senior","profession":"agriculture","title":"The operating-line ask","scenario":"Your operating-loan renewal meeting is next week, but you need the bank's answer on a $150,000 line increase before you can lock in spring inputs. Your email draft to your loan officer opens with three paragraphs recapping last season.","task":"Rewrite the email so the ask and the deadline are in the first sentence.","tips":["Lead with the number and the date you need an answer by.","Last season's story is support — put it after the ask.","One clear request per email."],"focus":["clarity","impact"],"placeholder":"I'm asking for a $150,000 increase to our operating line, and I need an answer by March 1 —"},
    {"id":"lead-agri-senior-02","level":"senior","profession":"agriculture","title":"The hail call","scenario":"A hailstorm just went through 400 acres of your corn two weeks before tassel. You're about to call your crop insurance agent, and your instinct is to describe the whole storm before saying you're filing a claim.","task":"Write the first two sentences of the call, leading with the claim.","tips":["First sentence: you're filing a claim, on which acres, for what.","The storm story is detail the adjuster will collect later.","Ask for the next step before you hang up."],"focus":["clarity","structure"],"placeholder":"I'm filing a hail claim on 400 acres of corn on the home farm —"},
    {"id":"lead-agri-senior-03","level":"senior","profession":"agriculture","title":"The plant-closure vote","scenario":"You chair the co-op board, and tonight the board votes on closing the aging fertilizer plant. Your draft opening walks through eighteen months of study before anyone hears what you're recommending.","task":"Write a 2-3 sentence meeting opener that states your recommendation first.","tips":["Name the recommendation and the vote in sentence one.","The eighteen months of study is your evidence, not your opener.","Directors decide better when they know where you stand from the start."],"focus":["structure","impact"],"placeholder":"I'm recommending we vote tonight to close the fertilizer plant by June 30."},
    {"id":"lead-agri-senior-04","level":"senior","profession":"agriculture","title":"Short on the contract","scenario":"Drought took your soybean yields down, and you'll be about 8,000 bushels short on your November contract with the elevator. You need to call your buyer, and you're tempted to open with the weather before admitting the shortfall.","task":"Write the first two sentences of the call, shortfall first.","tips":["Lead with the number you'll be short and the contract it hits.","Buyers respect early, plain warnings — they can still adjust.","Offer your proposed fix in the same breath: buy out, roll, or deliver what you have."],"focus":["clarity","impact"],"placeholder":"We're going to be about 8,000 bushels short on the November contract —"},
    {"id":"lead-agri-senior-05","level":"senior","profession":"agriculture","title":"The mid-harvest plan change","scenario":"The big combine is down with a broken feeder house, and the dealer can't get parts until Thursday. Your crew of five is waiting on a text telling them what changes. Your draft explains the breakdown before the new plan.","task":"Write one text that leads with what each person should do now.","tips":["First words: the new plan, not the breakdown.","Assign by name so nobody has to ask.","Keep the why to one clause at the end."],"focus":["clarity","concision"]},
    {"id":"lead-agri-senior-06","level":"senior","profession":"agriculture","title":"The vet voicemail","scenario":"You've got six steers bloating in the east lot and your vet's line went to voicemail. You tend to leave long messages that start with pleasantries and end with the emergency.","task":"Write a voicemail script that puts the emergency and the location first.","tips":["First sentence: what's wrong, how many head, where.","Say the callback number slowly, early, and twice.","Urgency should be unmistakable in the opening words."],"focus":["clarity","precision"],"placeholder":"Six steers bloating in the east lot at the home place — I need a call back now."},
    {"id":"lead-agri-senior-07","level":"senior","profession":"agriculture","title":"The early lease renewal","scenario":"Your best landlord's lease runs through next year, but you want to renew early and add a second parcel before another operator gets to her. Your letter draft spends two paragraphs on how the crops looked before making the ask.","task":"Write an opening line that puts the renewal ask up front.","tips":["Lead with what you're proposing: renew now, and add the 60 acres.","Crop condition is supporting evidence of your care, not the headline.","Name the next step — a call or a visit, with a date."],"focus":["clarity","structure"]},
    {"id":"lead-agri-senior-08","level":"senior","profession":"agriculture","title":"The counteroffer","scenario":"The dealer quoted $385,000 on the used combine and you're prepared to pay $350,000 with your trade. Your reply draft rambles about the machine's hours and tire wear before it names your number.","task":"Write a 2-3 sentence reply that leads with your offer.","tips":["State your number in the first sentence.","Hours and tire wear justify the number — they come second.","End with what happens if he accepts: when you'd close."],"focus":["clarity","impact"],"placeholder":"I'm at $350,000 with my trade — here's why that's the fair number."},
    {"id":"lead-agri-senior-09","level":"senior","profession":"agriculture","title":"The FSA deadline question","scenario":"You need to know whether your prevented-plant acres can still be enrolled before Friday's deadline. Your email to the county FSA office starts with the history of the wet spring instead of the question.","task":"Rewrite so the question is sentence one.","tips":["Ask the deadline question first, in one sentence.","Give only the facts they need to answer: acres, farm number, dates.","A clear question gets an answer before the deadline; a story might not."],"focus":["clarity","concision"],"placeholder":"Can I still enroll my 92 prevented-plant acres before Friday's deadline? Farm number is —"},
    {"id":"lead-agri-senior-10","level":"senior","profession":"agriculture","title":"Opening the succession talk","scenario":"After two years of putting it off, you've decided to start transferring machinery ownership to your son this year. The family is gathered at the kitchen table, and your instinct is to reminisce for ten minutes before saying what you've decided.","task":"Write the first two sentences of the meeting, decision first.","tips":["State the decision plainly: what transfers, to whom, starting when.","History and feelings matter — after the family knows the point.","A clear opening spares everyone the anxiety of guessing where this is going."],"focus":["clarity","impact"],"placeholder":"I've decided to start transferring the machinery line to Mark this year."},
    {"id":"lead-agri-senior-11","level":"senior","profession":"agriculture","title":"Two minutes at the township meeting","scenario":"The township board is voting on new road weight limits that would block your grain trucks during spring hauling. You get two minutes at the podium. Your notes start with thirty years of farming history.","task":"Write an opening sentence that states your position and what you're asking the board to do.","tips":["Position first: oppose, support, or amend — say which.","Your history earns you credibility in one clause, not one minute.","Name the specific change you want in the motion."],"focus":["impact","structure"]},
    {"id":"lead-agri-senior-12","level":"senior","profession":"agriculture","title":"The replant decision","scenario":"Your agronomist sent stand counts on the frost-damaged north farm and asked what you want to do. You've decided to replant the 120 acres. Your reply draft rehashes his whole report before giving the answer.","task":"Write a reply that gives the decision in sentence one.","tips":["Decision first: replant, which acres, what hybrid.","He wrote the report — don't summarize it back to him.","Add the one thing you need from him: seed order or a date."],"focus":["clarity","concision"],"placeholder":"Replant the full 120 on the north farm —"},
    {"id":"lead-agri-senior-13","level":"senior","profession":"agriculture","title":"The pickup-schedule ask","scenario":"Your milk processor's every-other-day pickup no longer works — the new tank fills in 36 hours. You need daily pickup starting next month. Your email draft opens with a history of your expansion.","task":"Write a 2-3 sentence email that leads with the request and the date.","tips":["The ask is sentence one: daily pickup, starting when.","The tank capacity is the one supporting fact that matters.","Make the reply easy: yes, no, or a call."],"focus":["clarity","structure"]},
    {"id":"lead-agri-senior-14","level":"senior","profession":"agriculture","title":"Telling the bank before it's late","scenario":"Cattle prices broke the wrong way and your December loan payment will be short unless you sell grain you'd planned to hold. You want your lender to hear it from you first, but your draft buries the news under market commentary.","task":"Write a 2-3 sentence message that states the situation in sentence one.","tips":["Lead with the fact: the December payment is at risk.","Then your plan — what you'd sell, what you're asking for.","Lenders reward early honesty; surprises cost you credibility you'll need later."],"focus":["clarity","impact"],"placeholder":"I want you to hear this from me early: the December payment is going to be tight."},
    {"id":"lead-agri-senior-15","level":"senior","profession":"agriculture","title":"The dividend headline","scenario":"The co-op board approved a $1.2 million patronage dividend — the largest in a decade. You're writing the newsletter announcement, and your draft opens with three paragraphs about the fiscal year before the news.","task":"Write the announcement's opening line, news first.","tips":["Members skim: put the dividend and the payout date in line one.","What made it possible comes second.","Say what each member should do, if anything."],"focus":["impact","concision"],"placeholder":"The board has approved a $1.2 million patronage dividend — checks mail October 15."},
    {"id":"lead-agri-senior-16","level":"senior","profession":"agriculture","title":"The offer call","scenario":"You've chosen your farm manager candidate after three interviews, and you're calling to make the offer. Your instinct is to recap the interview process before saying the words he's waiting for.","task":"Write the first two sentences of the call, offer first.","tips":["Sentence one: the job is his, and the salary.","Enthusiasm lands harder after the offer than before it.","Then the logistics: start date, next steps, when you need his answer."],"focus":["clarity","impact"]},
    {"id":"lead-agri-senior-17","level":"senior","profession":"agriculture","title":"The land conversation","scenario":"Your neighbor is 74, his kids live in the city, and word is he's thinking about winding down. You want to be the first call when he sells the east 80. You're writing him a note and keep hiding the point under small talk.","task":"Write a 2-3 sentence note that makes your interest plain in the first sentence.","tips":["Say it directly: you want to buy when he's ready.","Respect and directness can share a sentence.","Leave the door open — no pressure, just first call."],"focus":["clarity","audience"],"placeholder":"When you're ready to sell the east 80, I'd like to be your first call."},
    {"id":"lead-agri-senior-18","level":"senior","profession":"agriculture","title":"The incident report","scenario":"A new hire caught his glove in the auger yesterday — stitches, no permanent damage, back next week. You're reporting it to your workers'-comp carrier, and your draft narrates the whole afternoon before stating what happened and his condition.","task":"Write an opening that states what happened, the injury, and current status in two sentences.","tips":["Facts first: what happened, injury, status, date.","The sequence of the afternoon is detail for the claim file.","Precise and plain beats defensive and long."],"focus":["precision","clarity"]},
    {"id":"lead-agri-senior-19","level":"senior","profession":"agriculture","title":"The allocation request","scenario":"You need the irrigation district to approve moving 60 acre-feet of your allocation from the sold parcel to your home pivot before the season starts. Your letter opens with the story of the land sale.","task":"Write an opening line that states the transfer request and the deadline.","tips":["Request first: what's moving, from where, to where, by when.","The land sale is one sentence of context, not one paragraph.","Cite the parcel numbers so staff can act without a call back."],"focus":["clarity","precision"]},
    {"id":"lead-agri-senior-20","level":"senior","profession":"agriculture","title":"The early-delivery answer","scenario":"Your buyer emails: can you start delivering the contracted corn a week early? You can — the bins are full and trucks are free. Your reply draft wanders through your harvest progress before answering.","task":"Write a reply that answers in the first word or two.","tips":["Answer first: yes or no.","Then the one condition, if any.","Don't make a buyer dig for a yes — it's the easiest goodwill you'll earn all year."],"focus":["concision","clarity"],"placeholder":"Yes — we can start hauling Monday the 14th."},
    {"id":"lead-agri-senior-21","level":"senior","profession":"agriculture","title":"The bad-load warning","scenario":"Your first truckload of corn tested at the edge of the vomitoxin limit at your own probe, and three more loads from the same bin are scheduled today. You're calling the elevator, and your instinct is to explain the wet fall first.","task":"Write the first two sentences of the call, leading with the problem and what you've halted.","tips":["First sentence: what tested high and what you've stopped.","Elevators remember who self-reports and who gets caught.","Then the ask: retest, blend, or reroute — propose one."],"focus":["clarity","impact"],"placeholder":"My probe shows the corn from bin 4 near the vomitoxin limit — I've held today's loads until we retest."},
    {"id":"lead-agri-senior-22","level":"senior","profession":"agriculture","title":"The accountant question","scenario":"You need your accountant's answer on one thing: does the equipment transfer to your son trigger gift tax this year or can it wait until January? Your email draft explains the whole succession plan before asking.","task":"Rewrite so the question is the first sentence.","tips":["One question, sentence one.","Give the two facts needed to answer: the value and the timing options.","Save the full plan for the meeting you'll book anyway."],"focus":["clarity","concision"],"placeholder":"One question: does transferring the $240,000 machinery line to Mark this year trigger gift tax, or should we wait until January?"},
    {"id":"lead-agri-senior-23","level":"senior","profession":"agriculture","title":"The co-owner update","scenario":"You farm the home place your two sisters co-own. You sold the calf crop yesterday at a strong price, and their quarterly update is due. Your draft opens with weather and pasture notes before the number they actually watch for.","task":"Write an opening line that leads with the sale and the number.","tips":["Headline first: calves sold, head count, average price.","Their share and the payment date belong in the first two sentences.","Pasture notes are fine — below the money."],"focus":["clarity","structure"],"placeholder":"We sold the calves yesterday — 112 head at an average of $1,340."},
    {"id":"lead-agri-senior-24","level":"senior","profession":"agriculture","title":"The seed-order deadline","scenario":"The early-order discount on seed expires Friday — committing saves about $11,000 but locks your acres before you've settled the corn-bean split with your partner. Your text to her keeps burying the decision under the discount math.","task":"Write a message that leads with the decision needed and the deadline.","tips":["First line: the decision and Friday's deadline.","Then the trade-off in one sentence each way.","Propose your pick so she's confirming, not starting from zero."],"focus":["clarity","structure"],"placeholder":"Need your call by Friday: lock the seed order now and save $11,000, or wait —"},
    {"id":"lead-agri-senior-25","level":"senior","profession":"agriculture","title":"The gracious ask","scenario":"The extension agronomist spent half a day walking your fields last week, no charge. Now you need one more thing — her letter of support for your conservation grant, due in ten days. Your draft is all gratitude with the ask hidden in the last line.","task":"Write a message that pairs the thanks and the ask in the opening.","tips":["Put the ask where she can't miss it — first or second sentence.","Gratitude is real; it still shouldn't hide the request.","Give the deadline and offer to draft the letter for her."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-agri-senior-01","level":"senior","profession":"agriculture","title":"Yields, translated for the lender","scenario":"Your banker asked how harvest went. You're ready to talk hybrids, test weights, and the tile project that paid off. What she actually needs is whether the numbers cover the payments and next year's plan.","task":"Write a 2-3 sentence answer in the lender's terms: cash flow, coverage, and plan.","tips":["Her stake is repayment — lead with what the crop means for the loan.","Translate bushels into dollars against the budget you gave her.","Save the agronomy for the farm tour."],"focus":["audience","clarity"],"placeholder":"Harvest came in about 6% over the budget we built in March, so the operating note clears with room —"},
    {"id":"audience-agri-senior-02","level":"senior","profession":"agriculture","title":"The drift conversation","scenario":"Your new rural neighbor — moved out from the city last year — is upset that spray drifted onto her vegetable garden. She doesn't know what the product was or whether her tomatoes are safe, and she's scared more than angry.","task":"Write a 3-4 sentence explanation a non-farmer can understand, answering the question she actually has: is it safe?","tips":["Answer her real question first — safety — before process.","Name the product in plain terms and what the label says about gardens.","Say what you'll do differently; that lands better than a defense."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-03","level":"senior","profession":"agriculture","title":"First morning, no jargon","scenario":"Your new seasonal hire starts tomorrow — a college kid, never worked a farm. Your usual first-day text says \"meet at the shop, we'll be picking rock on the headlands then moving the drill.\" He won't know what half of that means.","task":"Rewrite the first-day message so someone with zero farm background knows where to be, what to bring, and what he'll be doing.","tips":["Beat the curse of knowledge: no shop-shorthand on day one.","Concrete beats correct: 'the metal building with the green door' works.","Tell him what to wear and bring — he doesn't know."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-04","level":"senior","profession":"agriculture","title":"Hedging at the kitchen table","scenario":"Your spouse handles the books but not the marketing, and the December statement shows a $40,000 loss on futures positions. It's not a real loss — the cash grain gained more — but the statement looks alarming and you owe a plain explanation.","task":"Explain in 3-4 sentences, in plain household terms, why the futures loss isn't money gone.","tips":["Start from her view: the scary number on the statement.","Use one everyday comparison — insurance premiums, locking a price.","End with the net: what the farm actually made on the grain."],"focus":["audience","clarity"],"placeholder":"That $40,000 looks like a loss, but it's one side of a price lock —"},
    {"id":"audience-agri-senior-05","level":"senior","profession":"agriculture","title":"Selling the transition to the foreman","scenario":"You're transitioning 300 acres to organic, and your foreman of 18 years thinks it's a fad that means more tillage and more headaches for him. He's not wrong about the work. You need him on board, not just compliant.","task":"Write a 3-4 sentence explanation aimed at his stake — his work, his crew, his pride — not the market's.","tips":["His question isn't 'why organic' — it's 'what does this mean for me.'","Acknowledge the true cost to him before the upside.","Give him a role in the decision that's still open: how, not whether."],"focus":["audience","impact"]},
    {"id":"audience-agri-senior-06","level":"senior","profession":"agriculture","title":"The annual report nobody reads","scenario":"You're writing the president's summary for the co-op annual report. Most members read one paragraph, standing at the mailbox. Your draft opens with governance procedure and saves the numbers members care about for page two.","task":"Write the one paragraph a mailbox reader needs: results, dividend, and what's changing.","tips":["Write for the standing-at-the-mailbox reader, not the auditor.","Three things they care about: did we make money, what do I get, what changes.","Plain numbers, no accounting terms."],"focus":["audience","concision"],"placeholder":"Your co-op made money this year: net savings of $2.1 million, with $1.2 million coming back to you —"},
    {"id":"audience-agri-senior-07","level":"senior","profession":"agriculture","title":"The five-year-lease pitch","scenario":"Your landlord is a retired teacher in the city who inherited the quarter section. You want a five-year lease so you can justify tile and lime investments. Your draft is full of agronomy; her actual concerns are steady income and whether the land is cared for.","task":"Write a 3-4 sentence pitch framed around her stake: security, stewardship, and simplicity.","tips":["Her question: is my land and income safe with you for five years?","Translate tile and lime into 'the land is worth more and yields hold.'","Offer proof she can check: soil tests, a yearly report, references."],"focus":["audience","impact"]},
    {"id":"audience-agri-senior-08","level":"senior","profession":"agriculture","title":"The drought quote","scenario":"The local paper calls: how bad is the drought for area farms? Your first instinct is technical — subsoil moisture, crop insurance triggers, basis. The readers are townspeople who want to know if farms and the local economy are in trouble.","task":"Give a 2-3 sentence quote a non-farm reader understands and trusts.","tips":["One primary audience: the town reader, not other farmers.","Concrete beats technical: what they'd see driving past a field.","Honest but measured — you're also speaking to your lender and landlords."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-09","level":"senior","profession":"agriculture","title":"Precision ag for the board","scenario":"You want the co-op board to approve a $600,000 precision-agronomy platform. Half the board are farmers over 60 who've heard tech pitches before. Your draft is vendor language: 'data-driven insights' and 'digital ecosystem.'","task":"Rewrite the core pitch in 3-4 sentences in terms this board trusts: member value, payback, and risk.","tips":["Strip the vendor language — this room has heard it all.","Altitude: they don't need how it works, they need what it earns.","Anchor to something the co-op already does well and this extends."],"focus":["audience","precision"],"placeholder":"This pays for itself if 200 members use it on half their acres —"},
    {"id":"audience-agri-senior-10","level":"senior","profession":"agriculture","title":"The market-stand question","scenario":"At your farm stand, a customer holding a quart of strawberries asks, 'Do you spray these?' You do, within label and withdrawal rules. A defensive lecture on integrated pest management will lose her; so will a dodge.","task":"Write a 2-3 sentence answer that is honest, plain, and keeps her trust.","tips":["Answer the question in the first sentence — yes, and here's what that means.","Translate rules into her terms: what's on the fruit when she eats it.","Confidence and openness sell more than perfection claims."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-11","level":"senior","profession":"agriculture","title":"The sustainability questionnaire","scenario":"Your grain buyer's parent company sent a sustainability questionnaire your contract renewal now depends on. You have real practices — cover crops, reduced tillage, nutrient plans — but your draft answers read like a defense of farming instead of speaking their framework.","task":"Rewrite one answer (3-4 sentences) in the buyer's frame: practices, acres, measurable outcomes.","tips":["Their reader is a corporate program manager scoring a form, not a farmer.","Match their vocabulary: practices, acres covered, outcomes, verification.","Numbers over narrative: acres, years, reductions."],"focus":["audience","precision"]},
    {"id":"audience-agri-senior-12","level":"senior","profession":"agriculture","title":"The safety rule that sticks","scenario":"After the auger incident, you're requiring lockout before anyone clears a jam — no exceptions. Your crew has heard safety talks before and tunes them out. A rule they don't believe in is a rule they'll skip at 11 p.m. in October.","task":"Write a 3-4 sentence announcement aimed at their stake, not the insurance company's.","tips":["Their stake: their hands, their family, not your premiums.","One concrete image of what almost happened beats ten policy sentences.","State the rule so simply it can't be misremembered."],"focus":["audience","impact"]},
    {"id":"audience-agri-senior-13","level":"senior","profession":"agriculture","title":"Explaining basis to the new analyst","scenario":"Your bank assigned a new credit analyst — sharp, but he's never priced a bushel. He asks why you haven't 'just sold at these good futures prices.' You need him to understand basis, because his write-up shapes your credit line.","task":"Explain in 3-4 sentences, in his financial vocabulary, why futures price isn't your sale price.","tips":["Use his language: the local cash price is futures minus a spread that moves.","One concrete number example does more than a definition.","Connect it to his job: what it means for your projected revenue."],"focus":["audience","precision"],"placeholder":"The futures board says $5.10, but my local cash price is that minus basis —"},
    {"id":"audience-agri-senior-14","level":"senior","profession":"agriculture","title":"Speaking the adjuster's language","scenario":"The insurance adjuster is coming Thursday to assess your wind-flattened corn. You're ready to talk about how bad it looks. Adjusters work in policy terms: cause of loss, date, affected units, appraised versus harvested.","task":"Write the 3-4 sentence summary you'll open with, framed in the adjuster's terms.","tips":["His frame: units, cause, date, acres — give it in that order.","'It looks terrible' isn't evidence; stand counts and photos are.","Ask what he needs from you before he leaves the yard."],"focus":["audience","precision"]},
    {"id":"audience-agri-senior-15","level":"senior","profession":"agriculture","title":"The plan for the non-farming heirs","scenario":"Two of your three children left the farm years ago. The succession plan gives your daughter the operation and the others land subject to a long-term lease. Your draft explanation is full of entity names and lease clauses they won't follow.","task":"Explain the plan to the non-farming heirs in 3-4 plain sentences: what they get, what they can and can't do, and why.","tips":["Their questions are simple: what do I own, what's it worth, what are the strings?","Plain words for the lease: 'the farm rents your land at market rate, reviewed every three years.'","Name the why honestly — keeping the farm operable — before they ask."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-16","level":"senior","profession":"agriculture","title":"One reader: the feeder","scenario":"The nutritionist rebalanced the ration and sent you two pages of changes. Tomorrow morning your feeder needs to load the wagon right. He needs pounds per head and load order — not crude protein percentages.","task":"Rewrite the change as a 3-4 line instruction for the person actually mixing feed.","tips":["One primary audience: the man at the loader, 6 a.m., gloves on.","His units: pounds, buckets, load order — not percentages.","Put what changed from yesterday first."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-17","level":"senior","profession":"agriculture","title":"Trucks and the township board","scenario":"Neighbors complained to the township about your grain trucks during harvest — dust, speed, early mornings. You'll speak at the board meeting. Your instinct is to explain harvest logistics; the board's frame is roads, safety, and voters.","task":"Write a 3-4 sentence statement in the board's frame that addresses safety and offers something concrete.","tips":["Their stake is complaints and road budgets, not your bushels.","Offer something real: routes, hours, a speed commitment for your drivers.","A specific offer beats a general defense in front of voters."],"focus":["audience","impact"]},
    {"id":"audience-agri-senior-18","level":"senior","profession":"agriculture","title":"Cover crops and the tidy landlord","scenario":"Your landlord drove past his quarter in November and called, unhappy that the field 'looks like it was never combined.' It's cereal rye you seeded as a cover crop. He measures good farming by clean, black fields — the way his father did it.","task":"Explain the cover crop in 2-3 sentences in his terms: the value of his land.","tips":["His stake is the land's worth and how the neighbors see his farm.","Translate: the green cover is holding his topsoil in place all winter.","Invite him to see the difference at the fence line in spring."],"focus":["audience","clarity"],"placeholder":"That green cover is a crop I planted to protect your soil over winter —"},
    {"id":"audience-agri-senior-19","level":"senior","profession":"agriculture","title":"The staffer email","scenario":"Your congressman's ag staffer asked for input on the crop insurance provisions in the next farm bill. Your draft is a farmer's complaint. Staffers act on emails that give them a district impact, a specific provision, and a clear ask.","task":"Write a 3-4 sentence email in the staffer's frame: provision, district impact, ask.","tips":["Her currency is district numbers: farms affected, dollars, jobs.","Name the exact provision — she's tracking dozens.","One clear ask she can put in a memo: support, oppose, or amend."],"focus":["audience","precision"]},
    {"id":"audience-agri-senior-20","level":"senior","profession":"agriculture","title":"Day one for the new manager","scenario":"Your new farm manager starts Monday. Your welcome note is full of shorthand — 'the Peterson quarter,' 'the old bin site,' 'the usual arrangement with Dale' — context he has no way of knowing.","task":"Rewrite a 4-5 sentence orientation note that assumes he knows nothing about the operation's history.","tips":["Every nickname needs a first-time introduction: who Dale is, where Peterson's is.","Give him the one thing to focus on in week one.","Tell him who to ask what — the unwritten org chart."],"focus":["audience","structure"]},
    {"id":"audience-agri-senior-21","level":"senior","profession":"agriculture","title":"Patronage, explained once","scenario":"A new member — young operator, first year with the co-op — asks what patronage dividends actually are and why part of his is 'retained.' The bylaws answer is accurate and useless to him.","task":"Explain patronage and retained equity in 3-4 sentences a first-year member understands.","tips":["Start from his experience: the business he did with the co-op this year.","'Retained' needs a plain translation: the co-op keeps part as your investment, paid out later.","Tell him when he actually sees cash — this year and down the road."],"focus":["audience","clarity"],"placeholder":"You did about $80,000 of business with us this year, so you own a share of the profit on it —"},
    {"id":"audience-agri-senior-22","level":"senior","profession":"agriculture","title":"The animal-welfare email","scenario":"A consumer found your beef at the local locker and emailed: how are the animals treated? She's genuinely asking, not attacking. Industry language — 'low-stress handling,' 'BQA certified' — will read as evasion to her.","task":"Write a 3-4 sentence reply in her language that describes what your cattle's daily life actually looks like.","tips":["Describe what she'd see if she visited: pasture, shade, feed, space.","Certifications support the answer; they aren't the answer.","Invite the visit — openness is the most convincing sentence."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-23","level":"senior","profession":"agriculture","title":"Telling the agronomist what you need","scenario":"Your agronomist keeps sending you 15-page field reports when what you need is a decision recommendation with a confidence level. The problem is you've never actually told him what altitude you want the information at.","task":"Write a 2-3 sentence message that tells him exactly what format and level of detail you need.","tips":["Calibrate the altitude explicitly: recommendation first, data on request.","Give him the template in one sentence: 'what you'd do, why, and how sure you are.'","Say what you'll stop reading — kindly, but clearly."],"focus":["audience","concision"]},
    {"id":"audience-agri-senior-24","level":"senior","profession":"agriculture","title":"The pest alert","scenario":"You found soybean gall midge in your county — first confirmed find. You're drafting an alert for the growers' association WhatsApp group, which ranges from 300-acre operations to 8,000-acre ones, some scouting weekly and some never.","task":"Write a 3-4 sentence alert that works for every grower in the group: what, where, and the one action to take.","tips":["Write for the least-informed reader without boring the best-informed.","One action everyone can do: where to look, what it looks like, who to call.","Location specifics build urgency: name the township, not just the county."],"focus":["audience","clarity"]},
    {"id":"audience-agri-senior-25","level":"senior","profession":"agriculture","title":"The grant reviewer","scenario":"You're applying for a rural-development grant to build an on-farm creamery. The reviewer is a state program officer who scores against criteria: jobs, community benefit, feasibility. Your draft summary is a story about your grandmother's recipes.","task":"Write a 3-4 sentence project summary in the reviewer's frame: jobs, dollars, community impact.","tips":["Score yourself against her rubric: jobs created, local spending, viability.","The grandmother story is one warming clause, not the lead.","Numbers she can put in her scoring sheet: positions, wages, timeline."],"focus":["audience","precision"]}
  ],
  "structure-that-carries": [
    {"id":"structure-agri-senior-01","level":"senior","profession":"agriculture","title":"The loan proposal pyramid","scenario":"You're asking the bank to finance a $900,000 machine shed and grain-handling upgrade. Your draft is twelve pages of quotes, yield history, and cash-flow tables with no organizing idea — the committee has to assemble the argument themselves.","task":"Write the governing idea and the three buckets that would organize the proposal.","tips":["One governing idea: this investment raises capacity and the numbers carry the payment.","Three buckets, no more: the return, the repayment, the risk controls.","Everything in the twelve pages should file under one bucket or get cut."],"focus":["structure","clarity"],"placeholder":"This upgrade adds 40% handling capacity and pays for itself in six years. Three things support that:"},
    {"id":"structure-agri-senior-02","level":"senior","profession":"agriculture","title":"SCQA for the merger letter","scenario":"Your co-op board is proposing a merger with the co-op two counties over, and you owe members a letter before the vote. You have all the facts but no frame — and a merger letter that reads like a data dump will breed suspicion.","task":"Draft the letter's opening using SCQA: situation, complication, question, answer — one sentence each.","tips":["Situation: what members know and agree on today.","Complication: what changed that makes standing still risky.","The question should be the one already on members' minds; then answer it plainly."],"focus":["structure","audience"],"placeholder":"Our co-op is financially sound today. But volume is shifting to..."},
    {"id":"structure-agri-senior-03","level":"senior","profession":"agriculture","title":"PREP on the panel","scenario":"You're on a young-farmers panel and the moderator asks: should a beginning farmer rent or buy land right now? You have a clear view but tend to think out loud, circling before you land anywhere.","task":"Give a spoken PREP answer — point, reason, example, point — in 4-5 sentences.","tips":["Point first: rent, in this market — then hold that line.","One reason, one real example from your own start.","Restate the point at the end so it's what they remember."],"focus":["structure","clarity"]},
    {"id":"structure-agri-senior-04","level":"senior","profession":"agriculture","title":"Ten wants, three buckets","scenario":"Your winter list of capital wants has ten items: a used semi, tile on the north 80, bin aeration, a bigger sprayer, shop heat, backup generator, scale, fencing, a skid steer, and pattern tile on the rented ground. The banker asked for your capital plan, not a wish list.","task":"Group the ten items into three named buckets and state the priority order.","tips":["Name buckets by purpose, not equipment type: revenue, risk, efficiency.","The grouping IS the argument — it shows you think in returns.","Items that don't fit a bucket are the first cut."],"focus":["structure","precision"]},
    {"id":"structure-agri-senior-05","level":"senior","profession":"agriculture","title":"The annual meeting skeleton","scenario":"You give the president's address at the co-op annual meeting in three weeks — 15 minutes, 200 members, dinner getting cold. Last year you wandered. This year you want a structure the room can follow without slides.","task":"Write the skeleton: one governing message and three sections, each in one sentence.","tips":["One message the sleepiest member takes home.","Three sections max — the year, the money, the road ahead.","Say the structure out loud at the start; a spoken map replaces slides."],"focus":["structure","impact"],"placeholder":"One message tonight: your co-op is strong and getting stronger. I'll cover three things —"},
    {"id":"structure-agri-senior-06","level":"senior","profession":"agriculture","title":"The land-purchase case","scenario":"The 160 next to your home farm is finally for sale at $2.1 million. You need your family partnership — spouse, brother, father — to agree within two weeks. You have a hundred reasons; a hundred reasons is no argument.","task":"State one governing idea and the three supports you'd build the family meeting around.","tips":["The governing idea answers 'why this, why now' in one sentence.","Pick your three strongest supports; the rest dilute.","Order them for your audience: your father cares about debt last or first?"],"focus":["structure","impact"]},
    {"id":"structure-agri-senior-07","level":"senior","profession":"agriculture","title":"The appeal letter","scenario":"The insurance company's appraisal on your flattened wheat came in far below your records, and you're appealing. Your draft letter mixes grievance, evidence, and requests in no order — easy for a reviewer to set aside.","task":"Outline the appeal in three labeled parts: what you're asking, the evidence, the requested next step.","tips":["A reviewer should get your ask from the first paragraph alone.","Group evidence by type: yield records, agronomist's counts, comparable fields.","End with one specific procedural request, not general dissatisfaction."],"focus":["structure","precision"]},
    {"id":"structure-agri-senior-08","level":"senior","profession":"agriculture","title":"Ordering the recovery update","scenario":"Three weeks after the flood, members want to know where the co-op stands. You have a jumble: the west elevator's status, insurance timelines, rail repairs, temporary receiving hours, staff overtime, and fall capacity. In your draft they arrive in the order you thought of them.","task":"Reorder the update under three headers a worried member would choose, and write the one-line summary that sits on top.","tips":["Lead with the summary judgment: can we take your harvest or not?","Headers in the member's priority order: now, this fall, the money.","Every fact files under a header or waits for the next update."],"focus":["structure","audience"],"placeholder":"Bottom line: we will be ready to take your harvest, at full capacity, by September 20."},
    {"id":"structure-agri-senior-09","level":"senior","profession":"agriculture","title":"PREP for the barn question","scenario":"Your banker asks, over coffee, why you want to expand the hog barn now with construction costs where they are. You know the answer cold, but it comes out as a pile of facts instead of an argument.","task":"Give a PREP answer in 4-5 sentences: point, reason, example, point.","tips":["Point: the contract makes now cheaper than waiting — say it first.","Your example should be a number he can check.","Land the plane: end on the point, not on a trailing caveat."],"focus":["structure","clarity"]},
    {"id":"structure-agri-senior-10","level":"senior","profession":"agriculture","title":"Grouping the exit chats","scenario":"Three seasonal workers didn't return this year, and your exit conversations produced a messy list: pay confusion, no schedule until Sunday night, the old bunkhouse wifi, shouting during harvest, no clear boss when you're away, paycheck errors twice.","task":"Group the complaints into 2-3 themes and name each theme in a phrase you'd act on.","tips":["Six complaints, probably three causes — find them.","Name themes as problems you can fix: 'nobody's in charge when I'm gone.'","The grouping tells you what to fix first; the raw list doesn't."],"focus":["structure","clarity"]},
    {"id":"structure-agri-senior-11","level":"senior","profession":"agriculture","title":"SCQA for the regulator","scenario":"You're requesting an amendment to your nutrient management plan after buying the neighboring dairy's ground. The agency reviewer reads hundreds of these; the ones with a clear frame move faster. Your draft opens mid-detail with spreading rates.","task":"Write the cover letter's first paragraph as SCQA — four sentences.","tips":["Situation: your current permitted plan, in one sentence.","Complication: the acquisition changed the acres and volumes.","Question and answer: what needs amending and what you're proposing."],"focus":["structure","precision"]},
    {"id":"structure-agri-senior-12","level":"senior","profession":"agriculture","title":"Structuring the recruiting pitch","scenario":"Your best farm-manager candidate has two other offers. You have thirty minutes at his kitchen table and a dozen selling points — wage, housing, autonomy, equipment, schools, equity path, hunting rights. Unstructured, it'll sound like begging.","task":"Organize the pitch: one headline reason and three supporting groups, one sentence each.","tips":["Lead with the one thing the other offers can't match.","Group the dozen points into three buckets: the job, the life, the future.","End with a specific next step and date, not 'think it over.'"],"focus":["structure","impact"]},
    {"id":"structure-agri-senior-13","level":"senior","profession":"agriculture","title":"The buyer meeting agenda","scenario":"Your annual sit-down with the processor covers price, quality penalties from last year, next year's volumes, and the new delivery windows. Last year the meeting ran long and settled nothing because everything got discussed at once.","task":"Write a three-item agenda with a decision attached to each item.","tips":["Three items max, hardest one second — not first or last.","Each item ends in a decision: agree, escalate, or drop.","Send it ahead; whoever writes the agenda shapes the meeting."],"focus":["structure","impact"]},
    {"id":"structure-agri-senior-14","level":"senior","profession":"agriculture","title":"The succession one-pager","scenario":"Your lawyer drafted forty pages of succession documents. Your family will not read forty pages, and misunderstanding breeds resentment. You need a one-page summary with a shape: who gets what, when, and what stays the same.","task":"Outline the one-pager: governing statement plus three sections with one-line contents.","tips":["Governing statement: the farm continues, and every child is treated fairly — then prove it.","Sections by reader question: ownership, operations, money.","Fair and equal are different words; the structure should make that distinction visible."],"focus":["structure","audience"],"placeholder":"The plan does three things: keeps the farm operating, treats all three of you fairly, and settles it while I'm alive to explain it."},
    {"id":"structure-agri-senior-15","level":"senior","profession":"agriculture","title":"The switching memo","scenario":"After 15 years you're moving your grain business from the local elevator to the shuttle loader 20 miles away — better bids, faster dumps. Your note to your own team explaining the change buries the decision under a history of grievances.","task":"Write the memo skeleton: decision first, then three reasons, then what changes operationally.","tips":["Decision in line one; nostalgia and grievances cut entirely.","Three reasons, each one line with a number attached.","End with the operational changes your drivers actually need."],"focus":["structure","concision"]},
    {"id":"structure-agri-senior-16","level":"senior","profession":"agriculture","title":"PREP on the radio","scenario":"The farm radio host asks you live: are solar leases good or bad for farm country? It's contentious — some neighbors signed, some organized against it. You have 45 seconds and no notes.","task":"Give a PREP answer in 4 sentences that takes a clear position without insulting either camp.","tips":["Point first, even on contested ground: 'good for some farms, wrong for others — the lease terms decide.'","One example listeners can picture.","Return to the point; don't trail off into both-sides mush."],"focus":["structure","clarity"]},
    {"id":"structure-agri-senior-17","level":"senior","profession":"agriculture","title":"Organizing the loss claim","scenario":"The derecho hit the whole operation: two bins crumpled, the machine shed roof, 600 acres flattened, a tractor under the shed, fences down, and spoiled grain in the damaged bins. The adjuster asked for 'a summary of losses' and your draft is a walk around the yard in no order.","task":"Group the losses into 3 categories with an estimated number on each, and write the one-line total on top.","tips":["Total first — the adjuster triages by size.","Categories by policy line, not by where you were standing: structures, equipment, crop.","One number per category, marked estimate or firm."],"focus":["structure","precision"]},
    {"id":"structure-agri-senior-18","level":"senior","profession":"agriculture","title":"The case for passing","scenario":"The auction flyer for the neighboring 240 is on every kitchen table, and your son wants to bid. You've run the numbers and the answer is no — at these prices it doesn't cash-flow even optimistically. Saying 'we can't afford it' will sound like fear, not analysis.","task":"Structure the case for passing: one governing idea and three supports, one sentence each.","tips":["Governing idea: passing is the aggressive move — it protects our ability to buy the right farm.","Supports with numbers: the cash-flow gap, the rate risk, the better use of the capital.","Address the emotional cost head-on as one of the three, not as an afterthought."],"focus":["structure","impact"],"placeholder":"We're not passing because we're timid — we're passing because this farm doesn't pay for itself at $14,000 an acre."},
    {"id":"structure-agri-senior-19","level":"senior","profession":"agriculture","title":"The dryer memo","scenario":"You're proposing the co-op invest $2.4 million in a new grain dryer before fall. The board packet needs a one-page memo. Your draft alternates between engineering specs, wait-time complaints, and finance — a braid nobody can follow.","task":"Write the memo's structure: recommendation line plus three sections with their headers.","tips":["Recommendation with the number and date on line one.","Sections: the problem members feel, the economics, the timeline and risks.","Specs go in an appendix; the board approves money, not augers."],"focus":["structure","clarity"]},
    {"id":"structure-agri-senior-20","level":"senior","profession":"agriculture","title":"SCQA at the township","scenario":"You're petitioning the township to join a county drainage improvement district. Half the room doesn't farm and hears 'drainage' as 'my taxes fund farmers' ditches.' You need a frame that starts from shared ground.","task":"Write your 4-sentence opening as SCQA, starting from what everyone in the room agrees on.","tips":["Situation must be genuinely shared: everyone's basements and roads flood too.","Complication: the current patchwork fails everyone, not just farms.","Answer with the petition — and who pays what, plainly."],"focus":["structure","audience"]},
    {"id":"structure-agri-senior-21","level":"senior","profession":"agriculture","title":"The safety talk that lands","scenario":"Your pre-harvest safety meeting is 20 minutes with a crew that's heard it all. Last year you read the insurance checklist aloud and watched eyes glaze. The content matters; the structure is what's failing.","task":"Structure the talk: one governing message and three sections, with the hook you'll open on.","tips":["Open on a story or a stat that isn't from a laminated card.","One message: nothing we haul is worth a hand.","Three sections tied to this farm's actual near-misses, not generic hazards."],"focus":["structure","impact"]},
    {"id":"structure-agri-senior-22","level":"senior","profession":"agriculture","title":"The year-end landlord letter","scenario":"You send all seven landlords a year-end letter. This year's draft mixes yield results, fertilizer receipts, next year's plans, a rent conversation you want to defer, and Christmas wishes — in one unbroken page.","task":"Reorganize into a structure with 3 labeled sections, and write the opening summary sentence.","tips":["Open with the sentence they most want: the land performed and here's proof.","Sections: this year's results, what I invested in your land, next year's plan.","The rent conversation gets its own separate letter — don't bury it here."],"focus":["structure","audience"],"placeholder":"Your farm had a strong year: 212-bushel corn, and I put $38 an acre back into the soil."},
    {"id":"structure-agri-senior-23","level":"senior","profession":"agriculture","title":"PREP on the agronomy department","scenario":"At the member forum, a longtime member asks you point-blank: should the co-op keep its agronomy department when the big retailers undercut it on price? The room goes quiet. You're the president; 'we're studying it' will satisfy no one.","task":"Give a PREP answer in 4-5 sentences with a real position.","tips":["Take the position first — keep it, change it, or wind it down.","Your reason should be the co-op's purpose, backed by one number.","Example: name what the department did this year that a retailer wouldn't."],"focus":["structure","impact"]},
    {"id":"structure-agri-senior-24","level":"senior","profession":"agriculture","title":"Bucketing the member survey","scenario":"The member survey came back with 340 free-text comments: fuel prices, the agronomist who left, slow dumps at harvest, the website, drying fees, hours at the branch, and everything else. The board wants 'what members are telling us' in five minutes.","task":"Define the 3 buckets you'd sort every comment into, and write the one-sentence takeaway for each.","tips":["Buckets by decision area, not by department: cost, service speed, people.","Force-rank the buckets by frequency — say the count.","One outlier comment worth quoting beats ten paraphrases."],"focus":["structure","concision"]},
    {"id":"structure-agri-senior-25","level":"senior","profession":"agriculture","title":"The lender's tour","scenario":"Your loan officer and her committee chair are touring the farm before the expansion decision. Two hours, four stops. Without a spine, farm tours become equipment show-and-tell; you need each stop to advance one argument.","task":"Plan the tour as a spoken structure: the headline you open with in the yard, and what each of the four stops proves.","tips":["Open with the thesis before anyone climbs in the truck.","Each stop proves one thing: capacity, efficiency, the constraint the loan fixes, the team.","Close where you started — restate the thesis at the last stop."],"focus":["structure","impact"],"placeholder":"Before we drive: everything you'll see today makes one point — this operation has outgrown its grain handling, and that's the only thing holding it back."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-agri-senior-01","level":"senior","profession":"agriculture","title":"The hedged bank email","scenario":"Your email to the loan officer reads: \"I think we could probably maybe look at possibly restructuring the equipment note if that's something you'd be open to considering at some point.\" You want the restructure. The hedges make you sound unsure of your own operation.","task":"Rewrite the sentence with the hedges cut.","tips":["One 'I'd like to' beats five 'maybes.'","Hedging doesn't soften an ask — it invites a no.","Keep one honest qualifier only if it carries information."],"focus":["concision","impact"],"placeholder":"I'd like to restructure the equipment note. Can we meet this month?"},
    {"id":"concise-agri-senior-02","level":"senior","profession":"agriculture","title":"Halve the newsletter column","scenario":"Your president's column for the co-op newsletter is 600 words. The editor gave you 300. Every paragraph opens with wind-up — \"As many of you are no doubt aware...\" — and every point is made twice.","task":"State the three cuts you'd make first, then write the new 2-sentence opening.","tips":["Cut every 'as you know' — if they know, why say it?","Each point once, in its strongest form.","The word count is a gift: it forces you to decide what matters."],"focus":["concision","clarity"]},
    {"id":"concise-agri-senior-03","level":"senior","profession":"agriculture","title":"The rambling voicemail","scenario":"You need to leave the buyer a voicemail: the last two loads graded better than contract, and you want the premium applied. Your practice run took 90 seconds and mentioned the weather twice.","task":"Write a 20-second voicemail script — roughly 3 sentences.","tips":["Name, purpose, ask, callback — nothing else.","If a sentence isn't about the premium, cut it.","Twenty seconds gets replayed; ninety gets deleted."],"focus":["concision","clarity"]},
    {"id":"concise-agri-senior-04","level":"senior","profession":"agriculture","title":"The 400-word lease letter","scenario":"Your lease renewal letter to the landlord runs 400 words. The actual content: you want to renew for three years at the same rent, and you'll re-gravel the driveway. Everything else is throat-clearing and weather.","task":"Rewrite the letter in under 100 words without losing warmth.","tips":["Warmth is one genuine sentence, not three paragraphs of padding.","The offer — term, rent, driveway — in the first two sentences.","Short letters get answered; long ones get set on the pile."],"focus":["concision","audience"],"placeholder":"I'd like to renew for three more years at the current rent — and this spring I'll re-gravel the driveway at my cost."},
    {"id":"concise-agri-senior-05","level":"senior","profession":"agriculture","title":"Cutting the meeting wind-up","scenario":"Your board meeting opener has become a ritual: \"Before I begin, I just want to take a moment to say a few words about how much ground we have to cover tonight...\" Ninety seconds of announcing that you're about to start.","task":"Write the replacement opening — one or two sentences that just start.","tips":["Meta-commentary ('I want to talk about...') is the thing to cut — just talk about it.","The agenda IS the opening: first item, go.","Respect for the room is shown in minutes saved, not in preamble."],"focus":["concision","impact"]},
    {"id":"concise-agri-senior-06","level":"senior","profession":"agriculture","title":"The doubled-up cover note","scenario":"Your cover note for the signed supply contract is stuffed with lawyer-flavored pairs: \"terms and conditions,\" \"each and every load,\" \"null and void,\" \"due and payable.\" You're a farmer, not a firm — and half of each pair is dead weight.","task":"Rewrite the note keeping one word from each pair.","tips":["'Terms' does everything 'terms and conditions' does.","Redundant pairs feel formal but read as fog.","Plain words signal confidence; borrowed legalese signals nerves."],"focus":["concision","precision"]},
    {"id":"concise-agri-senior-07","level":"senior","profession":"agriculture","title":"The bloated job posting","scenario":"Your farm-manager posting runs 700 words: a history of the farm, your philosophy, three paragraphs of 'the ideal candidate will demonstrate a commitment to excellence.' The actual job — duties, pay range, housing — is buried at the bottom.","task":"Rewrite the posting in under 150 words: the job, the pay, the place, the ask.","tips":["Candidates scan for pay, duties, and housing — lead with those.","'Commitment to excellence' describes nobody and attracts everybody.","Every sentence should help a good candidate decide to call."],"focus":["concision","audience"]},
    {"id":"concise-agri-senior-08","level":"senior","profession":"agriculture","title":"Halving the disaster update","scenario":"Your letter to landlords after the hailstorm runs two pages: the storm, the damage, insurance status, replant decisions, and reassurance — every point repeated in different words. Worried people need short and clear, not long and thorough.","task":"List the structure of a half-length version: what stays, in what order, and what gets cut entirely.","tips":["Worry reads slowly — front-load the reassurance with the number that proves it.","One fact, once. Repetition reads as anxiety.","The hour-by-hour storm story is the whole first cut."],"focus":["concision","structure"],"placeholder":"Your land is fine, the crop is insured, and here's what happens next —"},
    {"id":"concise-agri-senior-09","level":"senior","profession":"agriculture","title":"The apology-wrapped ask","scenario":"You need two extra weeks on your delivery window and your draft to the buyer apologizes four times before the ask: \"I hate to even bring this up... I know this isn't ideal... I'm so sorry to ask...\" All the apologizing makes the ask look bigger than it is.","task":"Rewrite the message with the ask up front and at most one clean acknowledgment.","tips":["Four apologies signal a crisis; one signals a routine adjustment.","State the ask, the reason, and the offer — done.","Confidence in the ask makes it easier to grant."],"focus":["concision","impact"],"placeholder":"I need to move our delivery window back two weeks, to the first half of December."},
    {"id":"concise-agri-senior-10","level":"senior","profession":"agriculture","title":"Un-nominalizing the grant","scenario":"Your conservation grant draft says: \"The implementation of irrigation efficiency improvements will result in the achievement of a reduction in water utilization.\" Buried in there is a plain sentence: new nozzles will cut water use.","task":"Rewrite the sentence with verbs doing the work — then find and fix one more like it in your own writing style.","tips":["Nominalizations hide the actor: 'implementation of' becomes 'we will install.'","Reviewers reward clarity; officialese doesn't score points.","If a sentence has three '-tion' words, it has zero energy."],"focus":["concision","clarity"],"placeholder":"We will install low-pressure nozzles, cutting water use by 20%."},
    {"id":"concise-agri-senior-11","level":"senior","profession":"agriculture","title":"The one-text instruction","scenario":"Rain is coming and you need the crew to switch from beans to corn on the far place after lunch. Your thumb-typed draft is a paragraph: reasoning, weather talk, and the instruction somewhere in the middle.","task":"Cut it to one text of two sentences or fewer.","tips":["Instruction first, reason in a clause if at all.","In the cab at 60 acres an hour, nobody reads paragraphs.","If it doesn't change what they do, it doesn't go in the text."],"focus":["concision","clarity"]},
    {"id":"concise-agri-senior-12","level":"senior","profession":"agriculture","title":"The family-meeting email","scenario":"Your email calling the family to a meeting about the land trust rambles for 300 words — history, feelings, scheduling philosophy — before the when and where. Two siblings will skim it on their phones and miss the date.","task":"Rewrite in 4 sentences: purpose, date and place, what to read beforehand, and one warm line.","tips":["Phones reward the first two lines; put the date there.","One attachment, named, with a reason to open it.","Warmth survives concision — one genuine sentence is enough."],"focus":["concision","audience"]},
    {"id":"concise-agri-senior-13","level":"senior","profession":"agriculture","title":"Ninety seconds of testimony","scenario":"The state committee cut public comments from three minutes to ninety seconds. Your prepared testimony on the drainage rule has an opening thank-you, your farm's history, and the point somewhere on page two.","task":"Cut the testimony to 90 seconds — roughly 120 words — keeping the ask and one piece of evidence.","tips":["Thank-yous cost ten seconds you don't have — one clause, moving on.","One number, one consequence, one ask.","End on the ask; committees remember last sentences."],"focus":["concision","impact"]},
    {"id":"concise-agri-senior-14","level":"senior","profession":"agriculture","title":"The equipment listing","scenario":"Your online listing for the 4WD tractor runs 250 words, half of it about how well you've cared for your equipment over the years. Serious buyers scan for hours, condition, price, and location — in about four seconds.","task":"Rewrite the listing in under 60 words with the facts a buyer scans for.","tips":["Hours, year, condition, price, town — above everything else.","'Well maintained' is noise; 'engine overhaul at 6,200 hours, receipts' is signal.","Every extra sentence buries the four facts that sell it."],"focus":["concision","precision"]},
    {"id":"concise-agri-senior-15","level":"senior","profession":"agriculture","title":"The mushy counter","scenario":"Your counter to the processor's price opens: \"We were sort of hoping to be somewhere in the neighborhood of a slightly better number if that's at all possible on your end.\" There's no number in it, and every word is a cushion.","task":"Rewrite the counter in one or two sentences with a number and no cushions.","tips":["A counter without a number isn't a counter.","'In the neighborhood of' tells them you'll take less.","State the number and one reason; then stop talking."],"focus":["concision","impact"],"placeholder":"I need $17.80. The last three loads graded premium and my trucking costs are up 12% —"},
    {"id":"concise-agri-senior-16","level":"senior","profession":"agriculture","title":"Minutes for members","scenario":"The board secretary's minutes run five pages. Your job is the member summary in the newsletter, and your draft is just shorter minutes — still chronological, still full of 'discussion was had regarding.'","task":"Write a 4-5 line summary organized by decision, not by clock.","tips":["Members want decisions and dollars, not the order things were discussed.","'Discussion was had' means nothing happened — cut or say what was decided.","One line per decision: what, how much, when it takes effect."],"focus":["concision","structure"]},
    {"id":"concise-agri-senior-17","level":"senior","profession":"agriculture","title":"The safety memo diet","scenario":"Your grain-bin entry memo is a full page from the insurer's template: definitions, legal citations, appendices. Your crew needs to know exactly one thing: nobody enters a bin without a second person and the winch harness, ever.","task":"Cut the memo to the 3-4 lines the crew must know and will actually read.","tips":["The rule, who it applies to, and the no-exceptions line.","Legal citations protect the file, not the worker — move them elsewhere.","Post-on-the-bin-door length: if it can't fit there, it's too long."],"focus":["concision","clarity"]},
    {"id":"concise-agri-senior-18","level":"senior","profession":"agriculture","title":"The dispute letter, decluttered","scenario":"Your dispute letter to the insurance company opens with three paragraphs of relationship history — years of premiums, past claims handled well, your disappointment. The reviewer needs the disputed number, your evidence, and your requested remedy.","task":"Cut the opening to two sentences that state the dispute and the ask.","tips":["Loyalty history isn't evidence — one clause at most.","Disputed amount and basis in sentence one.","Disappointment is felt; remedies are granted. Ask for the remedy."],"focus":["concision","precision"],"placeholder":"I dispute the $61,000 appraisal on claim 4471 — my yield records and the third-party stand counts support $89,000."},
    {"id":"concise-agri-senior-19","level":"senior","profession":"agriculture","title":"The invoice note","scenario":"Your note accompanying payment to the custom harvest crew thanks them in five sentences, questions one line item in the middle, and thanks them again. The question — a double-billed move charge — is easy to miss entirely.","task":"Rewrite so the payment, the question, and one thanks each get a single clear sentence.","tips":["Three jobs, three sentences: paid, question, thanks.","A question buried in gratitude doesn't get answered.","Number the invoice line you're asking about."],"focus":["concision","clarity"]},
    {"id":"concise-agri-senior-20","level":"senior","profession":"agriculture","title":"The cover letter that covers","scenario":"The cover letter for your succession binder to the family runs a full page and mostly repeats what's inside. A cover letter has one job: say what this is, what to read first, and what happens next.","task":"Cut it to 3 sentences.","tips":["If the binder says it, the letter doesn't.","Point to the one page to read first.","Name the meeting date where questions get answered."],"focus":["concision","structure"]},
    {"id":"concise-agri-senior-21","level":"senior","profession":"agriculture","title":"The double-filed application","scenario":"Your water-district application cover note repeats everything already in the form fields — parcel numbers, acre-feet, dates — then adds the one thing the form couldn't capture: the pump upgrade that changes your peak draw. That one fact is drowning.","task":"Rewrite the note to contain only what the form doesn't already say.","tips":["Never re-state the form — reviewers read it side by side.","The one new fact goes first and might be the whole note.","Shorter cover notes get read before the pile gets tall."],"focus":["concision","precision"]},
    {"id":"concise-agri-senior-22","level":"senior","profession":"agriculture","title":"The state-of-the-farm email","scenario":"Your annual email to your sisters about the home place runs 900 words. They love the farm but live in other states; they read for three numbers — income, expenses, their checks — and one honest paragraph about how things are going.","task":"Outline the halved version: the three numbers up top and what earns the one paragraph.","tips":["The money table first; narrative second.","One story from the year beats ten summaries.","If a sentence is really for you, not them, cut it — write it in your journal."],"focus":["concision","audience"]},
    {"id":"concise-agri-senior-23","level":"senior","profession":"agriculture","title":"The 30-second radio spot","scenario":"You're recording the co-op's harvest-hours radio spot. The draft has 110 words for a 30-second slot — it can hold about 75 — and ten of them are 'proudly serving the area's farm families for four generations.'","task":"Cut the spot to 75 words that lead with the information: hours, locations, phone.","tips":["Heritage lines are the first cut — listeners want hours, not history.","Say the phone number twice; cut something else to afford it.","Read it aloud with a stopwatch before calling it done."],"focus":["concision","audience"]},
    {"id":"concise-agri-senior-24","level":"senior","profession":"agriculture","title":"The five-paragraph complaint","scenario":"Your complaint to the seed company about the bad lot runs five paragraphs of frustration. The claim itself needs three facts: lot number, germination results versus tag, and what you want — replacement or refund.","task":"Cut the complaint to 3 sentences that a claims rep can act on immediately.","tips":["Anger is understandable and unprocessable — facts move claims.","Lot number, your test results, the remedy: one sentence each.","The shorter the complaint, the harder it is to shelve."],"focus":["concision","precision"],"placeholder":"Lot 23-1187 germinated at 71% against a 95% tag, tested twice."},
    {"id":"concise-agri-senior-25","level":"senior","profession":"agriculture","title":"The thread you owe one answer","scenario":"The group text with your crew has 30 messages debating tomorrow's plan — field order, who hauls, when the fuel truck comes. Everyone's waiting on you. The temptation is to reply to each point; the crew needs one message that ends the thread.","task":"Write the single message that settles everything: 4 lines or fewer.","tips":["Decisions only — don't re-litigate the debate.","One line per person or task; names first.","A message that ends a thread is worth ten that continue it."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-agri-senior-01","level":"senior","profession":"agriculture","title":"'A pretty good year' at the bank","scenario":"Your banker asks how the year went and you hear yourself say 'pretty good, all things considered.' She can't put 'pretty good' in a credit file. Vague answers make her do your work — or worse, guess low.","task":"Rewrite the answer with the two or three numbers that actually describe the year.","tips":["Replace 'pretty good' with yield, price, and the bottom line against budget.","Name the baseline: better than what, by how much.","Specific numbers signal you run the operation by them."],"focus":["precision","clarity"],"placeholder":"Corn averaged 214 against a 205 budget, we sold 60% above $4.90, and net is about $85,000 ahead of the plan you have on file."},
    {"id":"precision-agri-senior-02","level":"senior","profession":"agriculture","title":"'Way better' hybrid claim","scenario":"You're telling your partner the new hybrid did 'way better' on the test strips and you want it on 800 acres next year. An 800-acre seed decision deserves more than an adverb — she'll ask, and she should.","task":"Restate the claim with the from-to numbers and where they came from.","tips":["'Way better' becomes bushels per acre, across how many strips, on what ground.","One year on one farm is a lead, not a verdict — say so.","The size of the decision sets the standard of evidence."],"focus":["precision","structure"],"placeholder":"It beat our workhorse by 11 bushels across four strips on the home farm — one year, one soil type, so I'd go 300 acres, not 800."},
    {"id":"precision-agri-senior-03","level":"senior","profession":"agriculture","title":"The skeptic test on tile","scenario":"Your loan proposal claims the $220,000 tile project 'pays for itself.' The credit committee's skeptic will ask exactly how, and a round claim with no build folds under the first question.","task":"State the payback with its components: yield gain, acres, price, and the years to recover.","tips":["Break the claim into checkable parts: bushels gained × acres × price.","Name the assumption most likely to be attacked — the yield bump — and your source for it.","A number that survives a skeptic gets funded; a slogan doesn't."],"focus":["precision","impact"],"placeholder":"Tile adds a conservative 12 bushels on 160 wet acres — at $4.75 that's $9,100 a year, so the project recovers in under eight years before land-value gain."},
    {"id":"precision-agri-senior-04","level":"senior","profession":"agriculture","title":"Dates, not 'soon'","scenario":"Your email tells the buyer deliveries will start 'soon after harvest wraps up' and finish 'sometime in December.' He's scheduling trucks and unload crews — your adverbs are unusable to him.","task":"Rewrite the delivery commitment with dates, and a confidence where you're honestly unsure.","tips":["Every 'soon' becomes a date; every 'sometime' becomes a window.","If weather makes it uncertain, give the date with the condition: 'by the 10th, weather permitting — I'll confirm by the 1st.'","A date is a commitment he can build on; fog isn't."],"focus":["precision","audience"],"placeholder":"First loads move Monday, November 3, and we'll be done by December 12 — I'll confirm the final week by Thanksgiving."},
    {"id":"precision-agri-senior-05","level":"senior","profession":"agriculture","title":"So what for the yield map","scenario":"Your agronomist's report shows the west 40 of the rented quarter running 30% under the field average for the third straight year. You forwarded the map to your partner with 'interesting.' The data has a decision in it that nobody has said out loud.","task":"Write the what, so-what, now-what in three sentences: the finding, what it means, and the action.","tips":["The finding: which acres, how far under, how many years.","The meaning: those acres lose money at current rent.","The action: fix, re-negotiate, or give notice — pick one, with a date."],"focus":["precision","structure"],"placeholder":"The west 40 has run 30% under field average three years straight — at $260 rent those acres lose about $70 each. I want to renegotiate them out of the lease or tile them, decided before renewal on March 1."},
    {"id":"precision-agri-senior-06","level":"senior","profession":"agriculture","title":"The round number in the plan","scenario":"Your succession draft says the farm is worth 'about $8 million.' Your non-farming daughters' lawyer will ask where that number came from, and 'that's what land is going for' will make every other number in the plan suspect.","task":"Restate the valuation with its build: land, machinery, grain, and the basis for each.","tips":["Break the round number into parts a lawyer can verify.","Name the source for each: county comparables, dealer quote, market price on the date.","One well-supported number buys credibility for the whole plan."],"focus":["precision","clarity"],"placeholder":"The $8.1 million is 940 acres at the county's $7,400 average from three fall sales, $1.2 million in machinery off the dealer's appraisal, and grain marked at the December 12 cash bid."},
    {"id":"precision-agri-senior-07","level":"senior","profession":"agriculture","title":"Countering 'rents are up'","scenario":"Your landlord opens renewal with 'everybody says rents are way up this year.' You've done the homework: the county survey, three actual leases you know, and this farm's yield history. 'That's not what I'm hearing' will just trade rumors.","task":"Write a 2-3 sentence counter that replaces his hearsay with checkable numbers.","tips":["Cite a source he can look up himself: the extension survey, by name.","Anchor to this farm's actual productivity, not the county's best dirt.","Offer your number with its basis in the same breath."],"focus":["precision","impact"],"placeholder":"The extension survey has our soil class averaging $242, up $7 from last year — this farm has yielded 4% under county average the past five years, so I'm proposing $240."},
    {"id":"precision-agri-senior-08","level":"senior","profession":"agriculture","title":"'A lot of damage' claims nothing","scenario":"Your first note to the insurance agent says the windstorm did 'a lot of damage to a good part of the corn.' Adjusters pay on evidence, not impressions — and your vague first report sets the anchor for the whole claim.","task":"Rewrite the damage report with acres, stand counts, and what's documented.","tips":["'A lot' becomes acres affected and percent down, field by field.","Say what evidence exists: dated photos, stand counts, a third-party count.","Precision in the first report frames every conversation after it."],"focus":["precision","clarity"],"placeholder":"Roughly 380 of the 520 corn acres are affected: greensnap on 40-60% of stalks in the worst 200, confirmed by stand counts Tuesday with dated photos on file."},
    {"id":"precision-agri-senior-09","level":"senior","profession":"agriculture","title":"'We take good care of the land'","scenario":"The buyer's sustainability form asks you to describe your conservation practices, and your draft says you've 'always taken good care of the land.' True — and worth zero points, because the scorer needs practices, acres, and years.","task":"Rewrite the answer as three checkable facts: practice, acres, duration.","tips":["Convert values into verifiable specifics: cover crops on how many acres, since when.","Numbers score; heritage sentiments don't.","If a practice is documented — nutrient plan, soil tests — say where."],"focus":["precision","audience"],"placeholder":"Cover crops on 600 of our 940 acres since 2019, no-till on all soybean ground for 12 years, and a nutrient management plan updated annually with grid soil tests on file."},
    {"id":"precision-agri-senior-10","level":"senior","profession":"agriculture","title":"Breakeven, built in the open","scenario":"At the marketing club you say your corn breakeven is 'around $4.20.' A sharp neighbor asks what's in it — does that include land, family labor, depreciation? Around-numbers with hidden contents start arguments instead of settling them.","task":"State the breakeven with its three biggest components and what's deliberately excluded.","tips":["Show the build: inputs, land cost, machinery — per acre, then per bushel.","Name what's out: your own labor, or owned-land appreciation.","A number with visible contents can be debated usefully; a round one can't."],"focus":["precision","clarity"],"placeholder":"My $4.22 is $610 an acre of inputs, $265 cash rent equivalent, and $118 machinery and drying, over a 235 average — it excludes my own labor."},
    {"id":"precision-agri-senior-11","level":"senior","profession":"agriculture","title":"'Trending well' isn't a report","scenario":"The co-op manager's board report says agronomy sales are 'trending well' and staffing is 'mostly resolved.' As president, you can't let the board govern on adverbs — and you need to set the standard without humiliating him.","task":"Write the 2-3 sentence note asking for the numbers, and name the standard for future reports.","tips":["Ask for the from-to: sales versus last year and versus plan.","Set the template: every claim in the board packet carries a number or a date.","Firm on the standard, generous to the person."],"focus":["precision","audience"],"placeholder":"Before Thursday, can you turn 'trending well' into numbers — agronomy sales versus plan and versus last year? Going forward I'd like every packet claim to carry a figure or a date."},
    {"id":"precision-agri-senior-12","level":"senior","profession":"agriculture","title":"Jobs, counted for the grant","scenario":"Your creamery grant draft promises the project 'will create jobs and support the local economy.' The reviewer scores against a rubric: positions, wages, timeline. Your sentence is unscoreable.","task":"Rewrite the claim with positions, wages, and dates the reviewer can score.","tips":["Count the jobs: full-time, part-time, seasonal — separately.","Wages matter to the score: give the range.","Add the timeline: how many by month twelve, how many by year three."],"focus":["precision","audience"],"placeholder":"The creamery creates 4 full-time positions at $22-28 an hour within twelve months of opening, adding 2 more by year three, plus an estimated $180,000 a year in local milk purchases."},
    {"id":"precision-agri-senior-13","level":"senior","profession":"agriculture","title":"The feed result, from-to","scenario":"You're telling the nutritionist his ration change 'made a real difference' in the finishing pens. He changed three variables and needs to know exactly what moved, by how much, or he can't tell you which change did the work.","task":"Restate the result with the from-to numbers: conversion, days on feed, or gain.","tips":["'Real difference' becomes the metric and both endpoints.","Say the period and pen count so he can judge the sample.","Give him the anomaly too — data he'd want, not just praise."],"focus":["precision","clarity"],"placeholder":"Conversion went from 6.4 to 6.0 across both pens over 60 days, and days-to-finish dropped about a week — though pen 2 lagged pen 1 by more than I'd expect."},
    {"id":"precision-agri-senior-14","level":"senior","profession":"agriculture","title":"'Stretched thin' won't fund a hire","scenario":"You want the partnership to approve a third full-time employee, and your case so far is 'we're stretched thin and it's only getting worse.' Your brother will ask what that costs — and 'thin' has no answer in it.","task":"Make the case in 3 sentences with numbers: hours, overtime, and what the strain cost this year.","tips":["Count it: hours worked, custom work turned away, the breakdown that waited.","Put a dollar figure on the pain — that's what a wage competes against.","One concrete near-miss carries more than a season of 'busy.'"],"focus":["precision","impact"],"placeholder":"The two of us averaged 74-hour weeks from April through November, we turned away $40,000 of custom work, and the planter sat broken three days in May because nobody could get to it — that's more than a $58,000 wage."},
    {"id":"precision-agri-senior-15","level":"senior","profession":"agriculture","title":"The walk-away number","scenario":"Before Saturday's land auction you tell your son 'don't let it get away, but don't go crazy either.' That sentence sets no limit at all — and auctions are designed to move people who haven't set one.","task":"Write the bidding instruction with the exact walk-away number and the basis for it.","tips":["One number, stated as a wall: we stop at X, no matter the room.","Show the basis so the number holds under adrenaline: cash-flow at rent-equivalent.","Decide now what you'll both say when it passes X — silence, and leave."],"focus":["precision","impact"],"placeholder":"Our number is $11,800 an acre — that's the most it cash-flows at with $280 rent-equivalent and today's rates. At $11,850 we're spectators."},
    {"id":"precision-agri-senior-16","level":"senior","profession":"agriculture","title":"Verify before you repeat","scenario":"A member tells you the co-op's drying fees are 'double what the shuttle loader charges' and wants the board to act. Repeating an unchecked claim from the president's chair makes it true in the county's mind. You checked: it's 15% higher, for faster dumps.","task":"Write the 2-3 sentence reply that corrects the number without dismissing the concern.","tips":["Lead with the checked fact and its source.","Correct the number, honor the concern — fees are still higher.","Say what the difference buys, in one clause, without sounding defensive."],"focus":["precision","audience"],"placeholder":"I checked both rate sheets this week: we're 15% higher, not double — 4.5 cents against their 3.9 — and our average dump wait is 20 minutes against their hour-plus. Worth the board's look either way."},
    {"id":"precision-agri-senior-17","level":"senior","profession":"agriculture","title":"'Old and unreliable' won't move $2.4M","scenario":"Your case for the new co-op dryer keeps describing the current one as 'old and unreliable.' Directors have heard 'old' about every asset they own. The maintenance log and harvest wait-time data say it better — if you'd use them.","task":"Replace the adjectives with three numbers from the records: downtime, repair cost, member wait.","tips":["'Unreliable' becomes hours down during harvest, from the log.","'Old' becomes this year's repair bill against a new unit's payment.","Member wait times are the number directors feel — lead with it."],"focus":["precision","impact"],"placeholder":"The dryer was down 96 hours across the last two harvests, repairs ran $118,000 in three years, and members waited over two hours to dump on nine separate days last fall."},
    {"id":"precision-agri-senior-18","level":"senior","profession":"agriculture","title":"On the record, checkable","scenario":"Your drainage testimony draft says this was 'the wettest spring anyone can remember' and 'crops drowned all over the county.' Opposing counsel — or just a careful commissioner — will check. Memory-claims collapse; records don't.","task":"Rewrite the two claims with checkable figures and named sources.","tips":["Replace memory with the weather station: inches, against the 30-year average.","'All over the county' becomes prevented-plant acres from the FSA office.","On the record, only say what a document can back."],"focus":["precision","structure"],"placeholder":"The Fairmont station recorded 14.2 inches from April through June — 5.1 above the 30-year average — and county FSA certified 11,400 prevented-plant acres, the most since 1993."},
    {"id":"precision-agri-senior-19","level":"senior","profession":"agriculture","title":"The one number that tells the truth","scenario":"Your sisters ask how the farm is doing, and you could bury them in yields, prices, and weather. They co-own the land; there's one number that answers their actual question, and picking it is the skill.","task":"Choose the one number you'd lead the update with, and write the sentence that delivers it with context.","tips":["Pick the number that answers their stake: return on their land, this year versus normal.","One number with a comparison beats ten numbers without one.","Offer the detail behind it — don't send it uninvited."],"focus":["precision","concision"],"placeholder":"The number that matters to you: the home place returned $312 an acre this year, about 8% above our five-year average — happy to walk through the detail anytime."},
    {"id":"precision-agri-senior-20","level":"senior","profession":"agriculture","title":"The custom-rate quote","scenario":"The neighbor's widow asks what you'd charge to farm her 240 next year. 'Whatever's fair' feels neighborly and guarantees a misunderstanding by June. A precise quote protects the friendship better than a vague one.","task":"Write the quote: the per-acre rate, what it includes, what it doesn't, and the settlement date.","tips":["Name the rate and tie it to a source she can check — the extension custom-rate survey.","List inclusions and exclusions now, not at settlement.","Precision here is kindness: it's the vague deals that end friendships."],"focus":["precision","audience"],"placeholder":"I'd do it for $138 an acre — right at the extension survey average — covering planting, spraying, and harvest; seed, chemical, and fertilizer are yours at cost, settled by December 15 with every receipt."},
    {"id":"precision-agri-senior-21","level":"senior","profession":"agriculture","title":"Metered, not 'not much'","scenario":"The water district's reviewer questions your permit renewal, and your draft response says the operation 'doesn't use much water compared to some.' You have three years of meter records that say it precisely — comparatives without numbers read as evasion.","task":"Rewrite the response with metered acre-feet against your allocation, by year.","tips":["Give the meter readings: used versus allocated, each of three years.","Percentages help the reviewer: 'averaging 81% of allocation.'","Offer the records themselves — evidence offered freely reads as confidence."],"focus":["precision","clarity"],"placeholder":"Metered use was 388, 402, and 371 acre-feet over the past three seasons against a 480 allocation — averaging 81% — and the meter logs are attached."},
    {"id":"precision-agri-senior-22","level":"senior","profession":"agriculture","title":"The premium, earned on paper","scenario":"You want the mill to pay the high-protein premium on your wheat without probing every load. Your ask so far: 'our quality is always there.' The elevator's grading records for your last two years would make the case — if you assembled them.","task":"Write the 2-3 sentence ask built on the records: loads, average protein, and the consistency.","tips":["'Always' becomes the count: how many loads over spec, out of how many.","Average and worst-case both matter — consistency is the sale.","End with the specific arrangement you want."],"focus":["precision","impact"],"placeholder":"Of our last 94 loads, 91 graded over 14% protein with a 14.6 average and none under 13.8 — I'm asking for the premium schedule applied on delivery, with retest rights on any load you doubt."},
    {"id":"precision-agri-senior-23","level":"senior","profession":"agriculture","title":"'Everyone's switching' isn't evidence","scenario":"Your son wants to move the whole planter to the new high-speed system because 'everyone's switching to it.' Maybe they are; that's a fashion report, not a case. You want to say yes to evidence, not enthusiasm — and teach the difference kindly.","task":"Write your reply: what evidence would change your mind, stated specifically.","tips":["Turn the debate into a test: what result, on how many acres, would prove it.","Name your real concern as a number — stand quality at speed, cost per acre.","'Show me X and I'm in' is leadership; 'no' is just rank."],"focus":["precision","structure"],"placeholder":"Here's my yes: run it on 200 acres against our planter, and if stand counts hold within 2% at the higher speed and the math clears $12 an acre, we convert the fleet next winter."},
    {"id":"precision-agri-senior-24","level":"senior","profession":"agriculture","title":"The frost estimate, with error bars","scenario":"The buyer needs your best read on how much of the frosted edible-bean crop will make grade, today, before you can really know. A false-precise answer will be wrong; 'too early to tell' is useless to him. The skill is a calibrated estimate.","task":"Write the answer: your range, what drives it, and the date you'll firm it up.","tips":["Give the honest range, not a fake point: '60 to 75%.'","Name what moves the number — the next ten days' weather.","Commit to the date the estimate hardens; that makes the range usable."],"focus":["precision","audience"],"placeholder":"Best read today: 60 to 75% makes grade — the swing is whether we stay dry through pod fill. I'll have a firm number by September 20 after test pulls."},
    {"id":"precision-agri-senior-25","level":"senior","profession":"agriculture","title":"Audit your own 'conservative'","scenario":"Your hog-barn expansion pitch calls its assumptions 'conservative' three times. The lender's committee has read a hundred decks that said 'conservative' over rosy numbers. The word proves nothing; the assumptions, listed with sources, prove everything.","task":"Write the assumptions table in prose: the three key assumptions, each with its number and source.","tips":["Never say 'conservative' — show the assumption against the historical range.","Cite the source for each: contract terms, university budgets, your own five-year records.","Flag the one assumption you're least sure of yourself; candor disarms the committee."],"focus":["precision","impact"],"placeholder":"Three assumptions carry the case: contract price at $42 per head, straight from the signed Prestage terms; feed cost at $0.62 a pound, the top third of the five-year range; and 3% death loss against our actual 2.4% average. The one I'd stress-test is feed."}
  ],
  "executive-presence": [
    {"id":"presence-agri-senior-01","level":"senior","profession":"agriculture","title":"Own the land recommendation","scenario":"Your memo to the family partnership lays out three options for the Hendricks quarter — pass, buy at auction, or approach early with a private offer — with pros and cons for each, and stops. You've farmed forty years; they're waiting for your call, not a menu.","task":"Rewrite the close to state your recommendation and stand behind it.","tips":["A menu without a pick pushes your judgment onto people who hired it.","Name your recommendation in the first sentence, then the strongest reason.","Invite disagreement after the position, not instead of one."],"focus":["impact","clarity"],"placeholder":"My recommendation is the private offer, this month — at auction we'd bid against emotion, and passing means watching it go to the operation that outbids everyone. Push back if you see it differently."},
    {"id":"presence-agri-senior-02","level":"senior","profession":"agriculture","title":"Signpost the annual address","scenario":"Your fifteen-minute address to two hundred members has good content and no spoken map, so last year people drifted after minute four. A room can't follow what it can't anticipate.","task":"Write the three signpost sentences: the opening map, one mid-speech transition, and the close.","tips":["Open with the shape: 'three things tonight — the year, the money, the merger question.'","Transitions are one sentence: 'that's the year; now the money.'","The close tells them what you need: their questions, or their vote."],"focus":["structure","impact"],"placeholder":"Three things tonight: how the year went, where the money stands, and the merger question everyone's asking about."},
    {"id":"presence-agri-senior-03","level":"senior","profession":"agriculture","title":"Fact versus judgment on the manager","scenario":"In the board's closed session on the co-op manager's performance, your notes blend what happened — the inventory writedown, the missed hire — with what you conclude. Directors who dispute your conclusion will attack your facts unless the two are cleanly separated.","task":"Write two labeled lines: the facts a camera would agree with, then your judgment.","tips":["Facts first, undisputed and dated.","Then the judgment, owned as yours: 'my conclusion is —'","Separated, both get stronger; blended, both get argued."],"focus":["clarity","structure"],"placeholder":"Facts: the $340,000 writedown was found in an audit he didn't initiate, and the agronomist role has been open eleven months. My judgment: the problem is follow-through, not honesty — fixable, with conditions."},
    {"id":"presence-agri-senior-04","level":"senior","profession":"agriculture","title":"'We hope' won't get funded","scenario":"Your renewal meeting draft says you 'hope prices cooperate' and 'think things should work out on the payments.' Hope isn't a plan a lender can underwrite. You actually have a plan — hedges, insurance, a marketing floor — but your language hides it.","task":"Rewrite the two sentences with calibrated confidence: what's protected, what's exposed, what you'll do.","tips":["Replace 'hope' with the mechanism: hedged, insured, contracted.","Say the residual risk plainly — calibrated beats cheerful.","Sound like someone who has decided, because you have."],"focus":["clarity","impact"],"placeholder":"Sixty percent of the crop is priced above breakeven and revenue protection covers the rest to 85% — the exposure is basis on the last 40%, and I'll have it contracted by July."},
    {"id":"presence-agri-senior-05","level":"senior","profession":"agriculture","title":"The steady voice in week six","scenario":"Six weeks without rain, and the crew reads you like a barometer. This morning two of them asked, separately, whether they should be looking for winter work. Panic is contagious — and so is steadiness, if you say something real instead of something cheerful.","task":"Write the 3-4 sentences you'd say to the crew: honest about the drought, clear about their jobs.","tips":["Don't perform optimism — name the situation plainly first.","Then the decided things: payroll is secure, the plan for a short crop exists.","Steadiness is specifics from a person who has thought it through."],"focus":["impact","audience"],"placeholder":"It's dry and it may stay dry, so let me tell you what's actually decided: payroll is covered through winter regardless of this crop — insurance guarantees that."},
    {"id":"presence-agri-senior-06","level":"senior","profession":"agriculture","title":"The president takes a position","scenario":"For three board meetings you've moderated the merger debate without saying where you stand, telling yourself the chair should be neutral. The vote is in six weeks, members are asking what you think, and neutrality is starting to read as either fear or hidden agenda.","task":"Write the 3-4 sentences where you state your position while keeping the debate legitimate.","tips":["Say it plainly: 'I'll vote yes, and here's my reason.'","One reason, your strongest — not a re-run of the whole study.","Then protect the dissent: name what would change your mind."],"focus":["impact","structure"],"placeholder":"I've moderated this debate for three meetings without saying my view, and you deserve it: I'm voting yes, because standing alone our volume declines every year and the numbers say so."},
    {"id":"presence-agri-senior-07","level":"senior","profession":"agriculture","title":"Cut the credential apology","scenario":"You're on the state conference panel about farmland transition, and your prepared opener begins 'I'm no expert, I'm just a farmer, but...' You've transitioned a five-generation operation and sat on two boards. The apology isn't humility; it's asking the room to discount you.","task":"Rewrite the opener to state your ground without the disclaimer.","tips":["Replace 'just a farmer' with the experience that earned the seat.","Humility lives in how you treat questions, not in discounting yourself upfront.","State your credential in one factual clause, then make your point."],"focus":["impact","concision"],"placeholder":"I've spent six years moving a five-generation farm to the next one, and I'll tell you the mistake I'd undo first."},
    {"id":"presence-agri-senior-08","level":"senior","profession":"agriculture","title":"'It was decided' by whom?","scenario":"Your memo to the crew about dropping the far-south lease says 'it was decided that the arrangement would not be renewed.' You decided. The passive voice reads like the decision wandered in from nowhere — and invites relitigating it with whoever 'it' is.","task":"Rewrite the sentence in first person, owning the decision and the reason.","tips":["'I decided' closes the question of who to argue with.","Give the reason in the same sentence — owned decisions carry their why.","Passive voice in decisions reads as either evasion or committee mush."],"focus":["clarity","impact"],"placeholder":"I've decided not to renew the south lease — at the new rent it loses money in two years out of three, and I'd rather put the machinery hours on ground that pays."},
    {"id":"presence-agri-senior-09","level":"senior","profession":"agriculture","title":"'What would you do?'","scenario":"After the co-op forum, a young member corners you: he can rent 300 more acres at a high price or stay lean, and asks what you would do. The safe move is 'that's really your call.' It's also a small betrayal — he asked because your judgment is worth something.","task":"Give the spoken answer: your actual view, with its reasoning, plus the limits of your knowledge of his operation.","tips":["Answer the question — 'here's what I'd do' — before the caveats.","One reason from your own scar tissue beats three from theory.","Bound it honestly: what you'd need to know about his numbers to be sure."],"focus":["clarity","audience"]},
    {"id":"presence-agri-senior-10","level":"senior","profession":"agriculture","title":"Taking the loan to bid","scenario":"After twenty years with one bank, you're taking the expansion loan out for competing bids, and you owe your loan officer the news face to face. Your instinct is to apologize your way through it. But you're not doing anything wrong — you're running a business.","task":"Write the 2-3 sentences you'd open with: direct, unapologetic, and fair.","tips":["State it as normal business practice, because it is.","No apology — but give her the chance to compete: that's the respect.","Twenty years earns a heads-up, not a guilty conscience."],"focus":["clarity","impact"],"placeholder":"A loan this size, I owe it to the operation to take bids — you'll get the same package the other two banks get, and I'd genuinely like you to win it."},
    {"id":"presence-agri-senior-11","level":"senior","profession":"agriculture","title":"The replant call, calibrated","scenario":"Your partner asks whether the frosted corn will recover or needs replanting. You're about 80% sure it recovers, and the honest answer has a confidence level in it. 'It'll be fine' overstates; 'hard to say' understates what you actually know.","task":"Write the answer with your confidence stated and what would change the call.","tips":["Say the number: 'I'm about 80% it recovers.'","Name the check that settles it: growing-point splits on Thursday.","A calibrated call is a leadership act; false certainty is a gamble on your credibility."],"focus":["clarity","precision"],"placeholder":"I'm 80% it recovers — the growing point looked clean on the plants I split. I'll walk it again Thursday, and if new leaf isn't spiking by then, we replant Friday."},
    {"id":"presence-agri-senior-12","level":"senior","profession":"agriculture","title":"Instructions that hold at auction","scenario":"Your banker's on vacation, so your daughter will bid for the partnership at the machinery auction while you're at the hospital with your father. Your instructions need to carry your presence into a room designed to melt resolve.","task":"Write the bidding instructions: numbers, sequence, and the sentence that steadies her when the room heats up.","tips":["Exact ceilings per lot, written, no 'use your judgment' escape hatches.","Script the hard moment: what she does when bidding passes the ceiling.","Give her the sentence to hold onto: the numbers were decided in the calm."],"focus":["precision","impact"],"placeholder":"Combine tops out at $210,000, the header at $38,000, and when it passes the number you put your hands in your pockets — we decided these figures at the kitchen table for a reason."},
    {"id":"presence-agri-senior-13","level":"senior","profession":"agriculture","title":"Signposting the succession meeting","scenario":"The family meeting on the estate plan could sprawl into grievances and history if it has no spoken structure. As the one who called it, your opening map is what keeps four adults and two spouses on the rails for ninety minutes.","task":"Write the opening signpost, one transition, and the close for the meeting.","tips":["Map first: 'three parts — the plan, your questions, what happens next.'","Transitions give permission to move on: 'more on that one-on-one — next part.'","Close with what's decided, what's open, and the date of the next conversation."],"focus":["structure","audience"],"placeholder":"We'll do three things tonight: I'll walk the plan in twenty minutes, then every question gets airtime, then we agree on what happens next and when."},
    {"id":"presence-agri-senior-14","level":"senior","profession":"agriculture","title":"Holding the seed order","scenario":"Your seed rep — a friend of fifteen years — is pushing hard against your order cut, hinting that your loyalty discount and plot access ride on volume. The relationship is real; so is the decision. Presence is holding both without heat.","task":"Write the 2-3 sentence response that holds the decision and names the pressure without escalating.","tips":["Restate the decision once, plainly — repetition invites negotiation.","Name the tactic gently: 'if the discount depends on volume, tell me straight.'","Warm on the friendship, immovable on the order."],"focus":["clarity","impact"],"placeholder":"The order stands at 180 units — the acres just aren't there this year. If the discount or plot access changes at that volume, tell me straight and I'll plan for it."},
    {"id":"presence-agri-senior-15","level":"senior","profession":"agriculture","title":"Reporting the losing year","scenario":"The operation lost $140,000 and your sisters' annual update is due. The temptation is a fog of weather narrative and market blame. Co-owners can absorb a bad year; what corrodes trust is the sense that you're managing their feelings instead of reporting to them.","task":"Write the opening 3 sentences: the loss, the honest why, and the plan — no fog.","tips":["The number first, unsoftened.","Attribute causes honestly, including any call of yours that went wrong.","Presence in a bad year is a plan with dates, not an apology tour."],"focus":["clarity","impact"],"placeholder":"The farm lost $140,000 this year. Two-thirds of that was the drought; the rest was my call to hold unpriced grain into a falling market, which I won't repeat — here's what changes."},
    {"id":"presence-agri-senior-16","level":"senior","profession":"agriculture","title":"Owning the plant decision","scenario":"The fertilizer plant closure you recommended is done, and the transition has gone worse than you projected — members driving forty minutes, two good employees gone early. At the annual meeting you could hide behind 'the board voted.' You brought the motion.","task":"Write the 3-4 sentences that own the outcome without abandoning the decision.","tips":["Own the recommendation in first person before anyone asks.","Separate the decision from the execution: the closure was right, the transition plan was thin.","Say what you're fixing, with a date — ownership without a plan is just confession."],"focus":["impact","structure"],"placeholder":"The plant closure was my recommendation, and I still believe it was right — but the transition plan under it was mine too, and it was thin. Here's what we're fixing by spring."},
    {"id":"presence-agri-senior-17","level":"senior","profession":"agriculture","title":"The podium correction","scenario":"At the county zoning hearing, the previous speaker just told the room your feedlot 'dumps into the creek' — flatly false; your containment passed inspection in May. You have two minutes and a choice between anger, lawyer-speak, and presence.","task":"Write the correction: firm, factual, documented, and free of heat.","tips":["Correct the fact, not the person — no adjectives about the speaker.","Cite the checkable record: the inspection, the date, the agency.","One correction, said once, calmly — repetition and volume both read as doubt."],"focus":["clarity","impact"],"placeholder":"One correction for the record: our containment system was inspected by the state on May 14 and passed — the report is public, and I'll hand a copy to anyone who wants it tonight."},
    {"id":"presence-agri-senior-18","level":"senior","profession":"agriculture","title":"Invite the fight you might lose","scenario":"You've told the board you're recommending the $2.4 million dryer. Two directors clearly have doubts and are being polite about it. A recommendation that never meets real resistance is untested — and their silence now becomes sabotage later.","task":"Write the 2-3 sentences that state your position and then genuinely open it to attack.","tips":["Restate the recommendation, then ask for the strongest case against it — by name if needed.","Name your own weakest point first; it makes dissent safe.","'What am I missing' asked sincerely is presence, not weakness."],"focus":["impact","audience"],"placeholder":"My recommendation is the dryer, full stop — and the weakest part of my case is the throughput assumption, so before we vote I want the strongest argument against it on the table. Gene, you've got doubts; let's hear them."},
    {"id":"presence-agri-senior-19","level":"senior","profession":"agriculture","title":"Day one with the new manager","scenario":"Your new farm manager starts Monday — the first non-family manager in the operation's history. The first conversation sets whether he hears you as a boss with clear standards or an owner who'll hover. You want authority without micromanagement in the same five sentences.","task":"Write the expectations you'd state on day one: what you own, what he owns, and how you'll disagree.","tips":["Divide the decisions explicitly: his calls, your calls, joint calls.","Name how disagreement works before it happens.","Clear authority delegated once beats fuzzy authority renegotiated weekly."],"focus":["clarity","structure"],"placeholder":"Day-to-day agronomy and the crew are yours — I won't second-guess them. Land, capital over $25,000, and marketing stay mine. When we disagree, you'll get my reasons and a decision inside a day."},
    {"id":"presence-agri-senior-20","level":"senior","profession":"agriculture","title":"The floor, stated once","scenario":"Your marketing advisor keeps circling: 'so we're flexible below $4.60 if the carry improves, or...?' You've decided $4.60 is the floor on the remaining bushels. Every hedge-word you add reopens the question you've already closed.","task":"Write the one or two sentences that set the floor and end the circling.","tips":["State the number as a decision, not a preference.","Give the standing instruction so he can act without re-asking.","Then stop — trailing qualifiers unsell a decision."],"focus":["concision","impact"],"placeholder":"The floor is $4.60 on every remaining bushel — standing order. Sell any rally above it in thirds, and don't call me to reconfirm."},
    {"id":"presence-agri-senior-21","level":"senior","profession":"agriculture","title":"The coffee-shop no","scenario":"A neighbor half-asks, half-announces in front of three other farmers that he'll be renting your extra quarter next year 'since you've got more than you can handle.' The audience is the trap: he's betting you won't contradict him publicly.","task":"Write the spoken reply: a clear public no that leaves his dignity intact.","tips":["Correct the record in one calm sentence — the audience heard the claim, so they need to hear the answer.","No is complete without a justification you'd have to defend.","Offer him a private conversation if there's anything real to discuss."],"focus":["clarity","audience"]},
    {"id":"presence-agri-senior-22","level":"senior","profession":"agriculture","title":"Label the forecast","scenario":"Your pre-harvest note to the buyer mixes contracted certainties with hopeful projections in the same breath — '160,000 bushels coming your way.' If weather takes 20,000 of it, he'll remember a promise, not a forecast. Presence is labeling which is which before he has to ask.","task":"Rewrite the volume statement separating the committed from the projected.","tips":["Two labeled buckets: contracted-and-in-the-bin versus field estimate.","Give the projection its honest range and the date it firms up.","People forgive missed forecasts; they don't forgive fuzzy promises."],"focus":["precision","clarity"],"placeholder":"Committed and certain: the 90,000 contracted bushels, already in the bin. On top of that, the field estimate is 60,000 to 75,000 — I'll firm it by October 10."},
    {"id":"presence-agri-senior-23","level":"senior","profession":"agriculture","title":"The chair's landing","scenario":"Ninety minutes of hot debate on the drying-fee increase, and the board is circling the same three points for the third time. The chair's job now isn't neutrality — it's a fair summary and a call to decide. Rooms don't land themselves.","task":"Write the summary-and-call: both sides in a sentence each, then the motion to vote.","tips":["Summarize each side in its own strongest terms — both camps must nod.","Name what more discussion won't change.","Then call the question plainly; deciding is what the room came for."],"focus":["structure","impact"],"placeholder":"Here's where we are: one side says the fee increase funds the dryer members are begging for; the other says it lands hardest on the smallest farms. Another hour won't change either fact — I'm calling the vote."},
    {"id":"presence-agri-senior-24","level":"senior","profession":"agriculture","title":"The date, said out loud","scenario":"You've told the family 'a few more years' about retirement for six years running, and planning has quietly stalled around your vagueness — your son can't commit, your daughter-in-law is looking at jobs in the city. You've actually decided: March 2028. Saying it out loud is the act.","task":"Write the 2-3 sentences that commit to the date and what it makes possible.","tips":["Say the date without escape clauses.","Name what the date unlocks for each person waiting on it.","A real date can still flex later — but only a real date lets anyone plan."],"focus":["clarity","impact"],"placeholder":"March 2028 — that's when I step back to twenty hours a week and Mark takes operational control. It's on the calendar, and every plan we make from tonight builds toward it."},
    {"id":"presence-agri-senior-25","level":"senior","profession":"agriculture","title":"'Are you sure?' at the committee","scenario":"You've presented the expansion plan and the committee chair leans back: 'Are you sure about these numbers?' It's a test of posture as much as math. Overclaiming fails it one way; crumpling into qualifiers fails it the other.","task":"Write the spoken answer: calibrated confidence with the strongest and weakest points named.","tips":["'Sure of X, watching Y' is the shape of a trustworthy answer.","Name your most defensible number and your most exposed one, unprompted.","Composure under the question is half the answer they're grading."],"focus":["clarity","impact"],"placeholder":"Sure of the costs — those are signed bids, not estimates. The yield assumption is the one I watch, which is why the plan cash-flows even at ten percent under it."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-agri-senior-01","level":"senior","profession":"agriculture","title":"'Can you make the payment?'","scenario":"Halfway through the renewal meeting, the banker sets down her pen and asks flatly: 'Can you make the March payment or not?' You want to walk her through the marketing plan first. That's not what she asked.","task":"Write the answer: the direct yes, no, or conditional in sentence one, then the support.","tips":["Answer the actual question in the first sentence — yes, no, or 'yes, if.'","Then the mechanism: what's sold, what's insured, what covers it.","Leading with the plan instead of the answer reads as a no."],"focus":["clarity","impact"],"placeholder":"Yes — the payment's covered by grain already sold, sitting in the account. The plan I want to show you is about next year's payment, not this one."},
    {"id":"pressure-agri-senior-02","level":"senior","profession":"agriculture","title":"The hostile mic","scenario":"At the member forum a longtime member takes the mic: 'Why did the board raise its own per-diems the same year you raised our drying fees?' The room goes quiet. Both facts are true, and any hint of dodge will be the only thing anyone remembers.","task":"Write the spoken answer: acknowledge both facts, give the honest context, no defensiveness.","tips":["Concede the true facts immediately — fighting them loses the room.","Give the numbers plainly: what the per-diem change actually costs per member.","Answer the fairness question underneath, not just the arithmetic one."],"focus":["clarity","audience"],"placeholder":"Both true, and fair to put side by side. The per-diem change costs the co-op $4,100 a year — about eleven cents per member — and here's why the board did it anyway."},
    {"id":"pressure-agri-senior-03","level":"senior","profession":"agriculture","title":"The honest unknown at the creek","scenario":"The state inspector, standing at your lagoon, asks how much manure reached the creek before your crew caught the overflow. You genuinely don't know yet — the transfer pump ran unattended for somewhere between two and six hours. Guessing low on the record could look like concealment later.","task":"Write the answer: what you know, what you don't, and when you'll know it.","tips":["Separate the known — when it was found, when it was stopped — from the unknown.","Give the honest range and refuse the false point-estimate.","Commit to the date and method for the real number: pump logs, flow rate."],"focus":["precision","clarity"],"placeholder":"I won't guess on the record. What I know: the crew found it at 6:40 and stopped it by 7:00. The pump could have run two to six hours — I'll have the actual figure from the hour meter and flow rate by tomorrow noon, and you'll get it first."},
    {"id":"pressure-agri-senior-04","level":"senior","profession":"agriculture","title":"The loaded question","scenario":"The TV reporter at the water-quality hearing asks you on camera: 'Isn't it true that farming is poisoning this river?' The question is built so that a plain yes or no both convict you. Angry denial makes the evening news; so does a stammer.","task":"Write the on-camera answer: reject the frame calmly, replace it with your own, give one checkable fact.","tips":["Don't repeat the poison word — repeating the frame is accepting it.","Bridge to your frame in one move: what the data actually shows.","One specific, checkable fact beats three defensive generalities."],"focus":["audience","impact"],"placeholder":"The river data is public, so let's use it: nitrates at the Fairmont gauge are down 18% over ten years, and the buffer strips farmers here planted are part of why. There's more to do, and we're doing it."},
    {"id":"pressure-agri-senior-05","level":"senior","profession":"agriculture","title":"'Will you be short again?'","scenario":"Last year you delivered 8,000 bushels short and made the buyer whole. This year at contract signing he asks, not warmly: 'Am I going to get shorted again?' The temptation is a wounded defense of last year. He's asking about next year.","task":"Write the answer: the direct commitment, what changed, and what happens if weather repeats.","tips":["Answer forward, not backward — he asked about this year.","Name the concrete change: contracting 75% of APH instead of 90%.","Say how a short crop gets handled now — that's the real reassurance."],"focus":["clarity","impact"],"placeholder":"No — and here's what changed. I'm contracting 75% of proven yield instead of 90%, so a repeat of last year still fills your trucks; a normal year gives me bushels to sell on top."},
    {"id":"pressure-agri-senior-06","level":"senior","profession":"agriculture","title":"Mid-auction nerve check","scenario":"Bidding on the Hendricks quarter just passed $10,000 an acre, and your son leans over: 'Are we overpaying? Should we stop?' You have ten seconds between bids to answer, and the answer has to be a decision, not a discussion.","task":"Write the ten-second spoken answer that decides and steadies.","tips":["Answer the question first: yes we're fine, or yes we stop.","Anchor to the number set at the kitchen table, not the number in the room.","Ten seconds of calm decision beats thirty of shared doubt."],"focus":["clarity","concision"]},
    {"id":"pressure-agri-senior-07","level":"senior","profession":"agriculture","title":"'Why him and not me?'","scenario":"After the succession meeting, your daughter — the one who left for the city — asks the question under all her questions: 'Why does Mark get the farm and not me?' A dodge here costs you the relationship; so does a clumsy answer. It deserves the truth, said with care.","task":"Write the answer: direct on the reason, honest about the fairness question, clear on what she does get.","tips":["Answer the real question — the reason is his fifteen years of labor in it, so say that.","Don't pretend equal and fair are the same; explain the difference out loud.","Affirm what's hers, specifically, in the same breath."],"focus":["clarity","audience"],"placeholder":"Because he's put fifteen years of his working life into it, and the farm only survives with an operator — that's the whole reason. It isn't equal, and I won't pretend it is; here's why I believe it's fair."},
    {"id":"pressure-agri-senior-08","level":"senior","profession":"agriculture","title":"The violation, answered","scenario":"The inspector hands you a written finding: the chemical shed's containment doesn't meet the updated code. Your first instinct is to explain that it passed in 2019 and nobody told you the rule changed. True — and it reads as excuse-making if it comes first.","task":"Write the spoken response: acceptance, the fix with a date, then the one question you need answered.","tips":["Lead with what you'll do, not why it isn't your fault.","Ask the useful question: exact spec, deadline, re-inspection process.","Inspectors write reports; make the sentence they write about you a good one."],"focus":["clarity","structure"],"placeholder":"Understood — I'll have it brought to the current spec. What I need from you: the exact standard it's measured against, and whether thirty days is an acceptable timeline for re-inspection."},
    {"id":"pressure-agri-senior-09","level":"senior","profession":"agriculture","title":"'What's your plan B?'","scenario":"The loan committee member who's been quiet all meeting finally speaks: 'This all works if it rains. What's your plan if the drought repeats?' It's the best question in the room, and 'it won't be two years in a row' would be the worst possible answer.","task":"Write the answer: the concrete drought scenario, the numbers, and the pre-decided actions.","tips":["Treat it as the gift it is — the chance to show you've stress-tested.","Numbers under the stress case: insurance floor, cost cuts, the asset you'd sell.","Pre-decided beats improvised: name the trigger points."],"focus":["structure","precision"],"placeholder":"If it repeats, revenue protection floors us at $610 an acre, which covers operating and interest but not principal — so the pre-decided moves are deferring the machinery trade and selling the east 40 of pasture, in that order."},
    {"id":"pressure-agri-senior-10","level":"senior","profession":"agriculture","title":"The question you can't answer yet","scenario":"At the forum a member asks point-blank whether the board is talking about selling the elevator to the regional. There ARE confidential talks — exploratory, nothing decided. Lying is disqualifying; 'no comment' confirms everything; a full answer breaches the NDA the board signed.","task":"Write the spoken answer that is honest about the boundary without breaching it.","tips":["Never lie to members — one discovered lie ends a presidency.","Name the boundary honestly: 'there are conversations I can't detail yet.'","Commit to the date and forum where they'll hear everything."],"focus":["clarity","audience"],"placeholder":"I won't lie to this room: the board explores options every year, and some conversations carry confidentiality I have to honor. What I can promise — nothing gets decided without member notice, full information, and your vote."},
    {"id":"pressure-agri-senior-11","level":"senior","profession":"agriculture","title":"'Would you drink it?'","scenario":"At the town hall on the aquifer, a woman holds up a jar of well water and asks if you'd let your grandkids drink the runoff from your fields. It's theater, and it's also a sincere fear. Scoffing loses the room; a chemistry lecture loses it slower.","task":"Write the answer that honors the fear, answers honestly, and lands one fact.","tips":["Answer the human question first — her fear is the audience's fear.","Your own family's wells are your most credible fact: you drink this water too.","One number, said kindly, after the connection — not instead of it."],"focus":["audience","impact"],"placeholder":"My grandkids drink from the well two hundred yards from my corn — so yes, and I test it every year. Last reading was 4 parts per million nitrate, less than half the safety limit, and I'll show anyone the results."},
    {"id":"pressure-agri-senior-12","level":"senior","profession":"agriculture","title":"'Your numbers look rosy'","scenario":"The credit analyst slides your projection back across the desk: 'Every farmer shows me 220-bushel corn. Your county average is 194.' He's calling your core assumption inflated, with a number of his own. Protest is fatal; so is caving on a number you can defend.","task":"Write the response that meets his number with yours: specific, sourced, undefensive.","tips":["Engage his fact — it's real — then show why your farms differ from the average.","Your evidence: five years of your own APH, field by field, not optimism.","Offer the stress case unprompted: what the loan looks like at HIS number."],"focus":["precision","impact"],"placeholder":"Fair — the county average is 194, and it includes every rented-thin quarter in it. My five-year APH across these specific farms is 217, documented in the insurance records you have. And at your 194, the loan still services — tightly, but it does."},
    {"id":"pressure-agri-senior-13","level":"senior","profession":"agriculture","title":"The coffee-shop probe","scenario":"At the co-op counter, a neighbor asks — loudly enough for the bench to hear — 'So how bad did the hail get you?' The county gossip network is standing right there. Total candor feeds a week of talk; visible evasion feeds a worse week of it.","task":"Write the spoken answer: honest in direction, bounded in detail, closed with grace.","tips":["Give the true headline without the balance sheet.","Boundaries can be friendly: some things stay between you and the adjuster.","End it with a turn — ask about his beans — so the boundary doesn't hang."],"focus":["audience","concision"]},
    {"id":"pressure-agri-senior-14","level":"senior","profession":"agriculture","title":"The vet's hard question","scenario":"The vet, elbow-deep in the down cow, asks without looking up: 'How long was she down before you called me?' The true answer is since last night — your hired man noticed at evening chores and hoped she'd rise by morning. The temptation to shave six hours off is enormous and would poison her diagnosis.","task":"Write the honest answer, plus the process fix you'll state before she asks for one.","tips":["The clock matters medically — give it exactly, even when it embarrasses you.","Don't launder it through blame of the hired man; you own the protocol.","Name the fix unprompted: down animals get called in within the hour, period."],"focus":["clarity","precision"],"placeholder":"Since evening chores — about fourteen hours, and that's on my protocol, not on Dave. From today, any down animal gets you called within the hour, and I'd rather pay for the false alarms."},
    {"id":"pressure-agri-senior-15","level":"senior","profession":"agriculture","title":"Ambushed in the boardroom","scenario":"Mid-meeting, a director asks you to explain a $90,000 variance in the agronomy division — a detail from a report you haven't finished reading. Eleven people are watching. Bluffing a guess risks being wrong on the record; a flustered apology costs the chair its authority.","task":"Write the composed spoken response: what you know, what you'll find out, and by when.","tips":["Composure first: 'good catch' costs nothing and buys a beat.","Say plainly you won't guess — precision has a reputation to protect.","Commit to the answer with a deadline, then move the agenda on."],"focus":["clarity","impact"],"placeholder":"Good catch, and I'm not going to guess at eleven people's expense. You'll have the breakdown from me and the manager by Friday noon — next item."},
    {"id":"pressure-agri-senior-16","level":"senior","profession":"agriculture","title":"'Is the co-op in trouble?'","scenario":"After two staff departures and the delayed dividend, a member catches you at the scale and asks straight: 'Level with me — is the co-op in trouble?' The full answer is no, but with real challenges. Cheerful dismissal will read as spin; a hedge will read as yes.","task":"Write the answer: the direct no, the two honest challenges, and the number that backs the no.","tips":["Direct answer first, then the honest complications — that order is the credibility.","One hard number makes 'no' believable: equity ratio, cash position.","Respect the question — 'level with me' is an invitation to be trusted."],"focus":["clarity","impact"],"placeholder":"Straight answer: no — equity's at 62% and we're cash-positive every month this year. What's true is we lost two good people to the regional's wages and the dividend moved a quarter, and the board's dealing with both."},
    {"id":"pressure-agri-senior-17","level":"senior","profession":"agriculture","title":"The grade dispute","scenario":"Your buyer calls: the last three loads graded two points below contract spec and he's applying discounts. Your on-farm probe said the loads were fine. Somebody's sample is wrong, and 'your grader's broken' is an accusation you can't prove yet.","task":"Write the response: dispute the finding without accusing, propose the resolution process.","tips":["State your conflicting data as data, not as an attack on his.","Propose the neutral path: split samples, third-party grading on the next loads.","Keep delivering meanwhile if you can — stopping escalates before the facts are in."],"focus":["precision","structure"],"placeholder":"My probe on those same bins ran two points higher, so one of our samples is off and I don't know whose. Next three loads, let's pull split samples and send one set to the state lab — I'll ride with whatever it says, both directions."},
    {"id":"pressure-agri-senior-18","level":"senior","profession":"agriculture","title":"Three questions stacked","scenario":"A director unloads in one breath: 'What did the dryer study cost, why wasn't the board told before the invoice, and who approved it?' Three questions, ascending in heat. Answering them tangled — or answering only the comfortable one — makes it worse.","task":"Write the response that unpacks and answers all three, in order, one sentence each.","tips":["Name the structure out loud: 'three questions — taking them in order.'","Answer each fully, including the one that stings.","Unpacking calmly demonstrates the control the question implied you lacked."],"focus":["structure","clarity"],"placeholder":"Three questions, in order. The study cost $18,500. The board should have been told at the March meeting and wasn't — that's a process failure I own. I approved it, under the manager's discretionary limit, which is exactly the policy we should re-examine."},
    {"id":"pressure-agri-senior-19","level":"senior","profession":"agriculture","title":"The premise you won't accept","scenario":"At the hearing, the activist begins: 'Given that operations like yours cut every corner on animal welfare to make a dollar...' and then asks his question. Answering the question as asked swallows the premise in front of the cameras. Exploding at him makes his point for him.","task":"Write the response: reject the premise in one calm sentence, then answer what's legitimate underneath.","tips":["Name the move without heat: 'I don't accept the premise, so let me answer what's underneath it.'","One fact that contradicts the premise, checkable.","Then answer the fair question inside the unfair one — there usually is one."],"focus":["clarity","audience"],"placeholder":"I don't accept the premise — our death loss and vet records would embarrass that sentence, and they're auditable. But the fair question underneath is how anyone verifies welfare claims, so let me answer that one."},
    {"id":"pressure-agri-senior-20","level":"senior","profession":"agriculture","title":"'Why should we lend to you?'","scenario":"The new bank's regional credit officer opens with the bluntest question in banking: 'Why should we lend eight hundred thousand dollars to you?' You have sixty seconds before the meeting becomes about his questions instead of your answer. Modesty is expensive here; so is swagger.","task":"Write the sixty-second answer: track record, protection, and character, each with a number or fact.","tips":["Three planks: never missed a payment, how the downside is capped, who vouches.","Numbers over adjectives: years, ratios, the drought year you still paid.","Calibrated pride is the register — you're stating facts, not begging."],"focus":["impact","structure"],"placeholder":"Because the record says I repay: twenty-two years, zero missed payments, including 2021 when the drought took forty percent of the crop. The loan's secured at under sixty percent of appraised value, and my current lender will tell you the only reason I'm here is rate."},
    {"id":"pressure-agri-senior-21","level":"senior","profession":"agriculture","title":"The lawyer's 'what if'","scenario":"Your estate lawyer asks the question you've been avoiding: 'What happens to this plan if Mark leaves farming — divorce, injury, or he just quits?' You don't have an answer. Pretending you do wastes her expertise; the gap she found is exactly what you're paying her to find.","task":"Write the honest response: admit the gap, add what you have decided, and set the work.","tips":["'I don't have an answer' is a strong sentence when followed by a plan to get one.","Give her the raw material: what you'd want in each scenario, even roughly.","Set the deadline for closing the gap — hers and yours."],"focus":["clarity","structure"],"placeholder":"I don't have an answer, and that's a real hole. Roughly: injury shouldn't cost him the farm, quitting shouldn't strand the land. Draft me two or three structures that do that, and I'll pick one before Christmas."},
    {"id":"pressure-agri-senior-22","level":"senior","profession":"agriculture","title":"Outlasting the silence","scenario":"You named your price on the hay contract — $185 a ton, delivered — and the feedlot manager has said nothing for ten full seconds, studying his coffee. Every fiber wants to fill the silence with 'but I could sharpen that a little.' The silence is the negotiation.","task":"Write what you say next — or the discipline of saying nothing — and the one sentence you'll use if he stays silent past comfort.","tips":["The first price cut offered into silence is a bid against yourself.","If you must speak, add value, not discount: firm the terms, don't soften the number.","A calm restatement beats a nervous improvement every time."],"focus":["impact","concision"]},
    {"id":"pressure-agri-senior-23","level":"senior","profession":"agriculture","title":"The retirement question, publicly","scenario":"During annual-meeting Q&A, a member asks with a grin: 'So when are you finally going to retire and let somebody younger run this board?' Laughter, but the question is real and the room wants a real answer. You've decided to serve one more term, then step down.","task":"Write the spoken answer: good-humored, direct, and actually informative.","tips":["Match the humor for one beat, then answer straight — the room notices dodges even in laughter.","Give the actual plan: one more term, then done, and why.","Name what you're doing about succession — that's the responsible version of the answer."],"focus":["audience","clarity"]},
    {"id":"pressure-agri-senior-24","level":"senior","profession":"agriculture","title":"Correcting the stat, not the man","scenario":"At the public hearing, a speaker claims 'farmers around here collect half a million each in subsidies while our roads crumble.' The real county average is a fraction of that. He's a neighbor and a taxpayer; humiliating him wins the point and loses the township.","task":"Write the correction: the accurate number with its public source, delivered without a scalp.","tips":["Correct the number, credit the concern — roads and budgets are legitimate.","Cite where anyone can check: the payment database, the FSA county office.","Leave him a graceful exit; you'll share a fence line with him for decades."],"focus":["precision","audience"],"placeholder":"The payment data's public, so let's get the number right together: the county average is about $14,000 a farm, not half a million — it's all searchable by name. His point about the roads still deserves an answer, and here's mine."},
    {"id":"pressure-agri-senior-25","level":"senior","profession":"agriculture","title":"Dawn after the fire","scenario":"The dairy barn burned at 2 a.m. — cows out safe, building gone, cause unknown. At 6:40 the county paper calls for a statement while the ash is still warm and you know almost nothing for certain. Whatever you say becomes the record; speculation about the cause could void the insurance investigation.","task":"Write the 3-4 sentence statement: confirmed facts only, no speculation, and the next update.","tips":["State only what's confirmed: fire, time, animals safe, no injuries.","Refuse cause speculation explicitly — 'that's the fire marshal's to determine.'","Give the next-update commitment so the vacuum doesn't fill with rumor."],"focus":["precision","clarity"],"placeholder":"The barn burned early this morning; every animal is out and nobody was hurt — that's what I know for certain. The cause is the fire marshal's to determine, and I won't guess ahead of him. I'll have more for you tomorrow."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-agri-senior-01","level":"senior","profession":"agriculture","title":"Before and after for the grain system","scenario":"Your $900,000 grain-handling pitch to the bank is all specs and quotes. The committee has never sat in a truck line at your yard during harvest. Until they feel the bottleneck, the number is just big; the before-and-after is what makes it inevitable.","task":"Write the 3-4 sentence before/after that opens the proposal.","tips":["Make 'today' concrete and costly: trucks idling, the combine parked by 4 p.m.","Make 'after' measurable: bushels per hour, days saved, custom income unlocked.","The gap between the two pictures is the argument — let it do the work."],"focus":["impact","structure"],"placeholder":"Today, harvest stops when the trucks do: the combine sits idle ninety minutes a day waiting on the auger, and we quit at 4 to beat the elevator line. With this system, we dump in eight minutes, run the combine to dark, and cut twelve days off harvest — twelve days of October weather risk, gone."},
    {"id":"narrative-agri-senior-02","level":"senior","profession":"agriculture","title":"The cost of dry feet, delayed","scenario":"Your brother keeps deferring the tile decision with 'the crops were fine this year.' True — it was a dry year. Your case keeps failing because it's framed as a benefit of acting instead of a cost of waiting, and nobody feels a benefit they've never had.","task":"Write the stakes as the cost of doing nothing: dollars per wet year, made concrete.","tips":["Frame inaction as the decision it is — 'not tiling' costs money in two years out of five.","Use the wet years he remembers: 2019's drowned-out acres, by name.","A recurring cost beats a one-time benefit in the gut, even at the same math."],"focus":["impact","precision"],"placeholder":"Passing on tile isn't neutral — it's choosing to lose $34,000 every wet year. In 2019 we drowned out 60 acres on that quarter; at today's prices that one spring costs more than half the tile job."},
    {"id":"narrative-agri-senior-03","level":"senior","profession":"agriculture","title":"Pre-empting the rate objection","scenario":"At tonight's family meeting on the land purchase, your father will say what he's said all winter: 'Nobody buys land at these interest rates.' If it lands as a rebuttal to your pitch, the meeting is over. If you raise it first — with respect and an answer — it becomes your strongest moment.","task":"Write the 2-3 sentences that name his objection before he can and answer it.","tips":["Raise it in his words — he should hear his own argument stated fairly.","Answer with structure, not dismissal: the seller terms, the refinance plan.","Pre-empting says you've done his thinking plus yours; rebutting says you weren't listening."],"focus":["structure","audience"],"placeholder":"Dad's going to say it, so I will: nobody buys land at these rates. He's right that the rate is the risk — which is why the offer is built on seller financing for five years, and we refinance when rates break, not before."},
    {"id":"narrative-agri-senior-04","level":"senior","profession":"agriculture","title":"The merger, told as a story","scenario":"Your merger letter to members is a wall of ratios and synergy estimates. Members don't vote for ratios; they vote for a future they can picture against one they fear. The facts need a before-and-after that a mailbox reader feels in thirty seconds.","task":"Write the 3-4 sentence narrative core of the letter: where standing alone leads, where merging leads.","tips":["Paint the do-nothing future honestly: volume drifting to the shuttle loader, services thinning.","The merged future in member terms: agronomists on staff, competitive bids, the branch stays open.","Contrast, not catastrophe — respect them enough to keep both pictures true."],"focus":["impact","audience"],"placeholder":"Standing alone, the next ten years look like the last five: volume drifting to the shuttle loader, one agronomist doing three counties' work. Merged, your co-op bids grain against the majors and the Fairmont branch stays open — the study says so and members can read every page."},
    {"id":"narrative-agri-senior-05","level":"senior","profession":"agriculture","title":"Her land, her legacy","scenario":"You want a five-year lease from the retired teacher who inherited the quarter. Your last letter argued yield data and tile economics — your story, not hers. What she has is her father's farm and a fear of choosing the wrong tenant. Persuasion means telling the story where she's the protagonist.","task":"Write the 3-4 sentence pitch framed as her story: what her land becomes under a five-year commitment.","tips":["Her before/after, not yours: the land her father left her, kept improving.","The five years is what lets you invest in HER asset — frame every improvement as hers.","Offer the proof that continues her story: the annual report, soil tests over time."],"focus":["audience","impact"],"placeholder":"Your father built that farm's soil for forty years, and a year-to-year tenant has no reason to keep building it. Five years lets me put tile and lime into your land — improvements that stay with the quarter, not with me — and every fall you'll get the report and soil tests that prove it's better than the year before."},
    {"id":"narrative-agri-senior-06","level":"senior","profession":"agriculture","title":"Succession as continuity","scenario":"You've been describing the succession plan to the family as a transaction — who gets what, when. Your daughter hears loss; your son hears burden; your wife hears the end of something. The same plan, framed as the farm's fifth handoff since 1911, changes what everyone hears.","task":"Write the 3-4 sentence opening that frames the transfer as continuity, then lands the first concrete step.","tips":["Anchor in the pattern: this farm has changed hands four times and survived each one.","The frame is 'the next chapter,' but it must end in a concrete step, not a sentiment.","Name what stays unchanged — the land, the name on the mailbox — before what changes."],"focus":["impact","structure"],"placeholder":"This farm has been handed off four times since 1911, and every handoff felt like an ending to somebody — and became the reason it's still ours. This is the fifth. The land stays, the name stays; what changes is whose signature orders seed, starting with the machinery line in January."},
    {"id":"narrative-agri-senior-07","level":"senior","profession":"agriculture","title":"The drought, sized for the district","scenario":"The congressman's staffer needs to make the drought real to a boss juggling forty issues. Your data — rainfall deficits, yield losses — is accurate and forgettable. One farm's story with the district's numbers attached is what survives into her memo.","task":"Write the 3-4 sentence version for her memo: one concrete story carrying the district-wide numbers.","tips":["Lead with one picturable farm — yours — then zoom to the district total.","Numbers she can quote: farms affected, dollars lost, the program provision that helps.","End with the ask her boss can act on: co-sponsor, sign the letter, visit."],"focus":["audience","impact"],"placeholder":"On my farm, the creek that's run since my grandfather's time went dry July 4th — and mine is one of 1,100 district farms in the disaster zone, out roughly $60 million together. The emergency haying provision would put feed on those farms in weeks; we're asking the congressman to co-sponsor."},
    {"id":"narrative-agri-senior-08","level":"senior","profession":"agriculture","title":"The creamery, framed as the bridge","scenario":"Your creamery pitch to the co-op board and the grant office reads like an equipment list. The story underneath — milk leaving the county at commodity price and coming back as someone else's branded butter — is doing no work. Frame the gap, then the bridge.","task":"Write the 3-4 sentence narrative: where the milk's value goes now, where it could stay, and the bridge.","tips":["Name the gap: the value-add happens 200 miles away, to your milk.","The after: the county keeps the margin, the jobs, and the label.","The creamery is the bridge — one sentence, with the number it carries across."],"focus":["impact","structure"],"placeholder":"Every day, forty thousand pounds of this county's milk leaves at commodity price and comes back as butter with someone else's town on the label — and their margin. The creamery keeps that margin here: four jobs, and about $180,000 a year that currently drives away in a tanker."},
    {"id":"narrative-agri-senior-09","level":"senior","profession":"agriculture","title":"'We tried that in '09'","scenario":"Before you've finished the precision-ag proposal, the senior director will say it: 'We bought the yield-mapping system in '09 and it collected dust.' He's right, and every younger director knows he'll say it. The objection is a memory — so the answer has to honor the memory and then distinguish it.","task":"Write the pre-emption: concede '09 fairly, then name the two things that make this different.","tips":["Tell his story accurately first — a strawman concession persuades no one.","Then the specific differences: the agronomist on staff now, members already using the data.","Let '09 become evidence FOR you: we know exactly how this fails, so we built against it."],"focus":["structure","audience"],"placeholder":"Gene's right about '09 — we bought mapping hardware nobody was hired to use, and it gathered dust. That failure is the design spec this time: the proposal funds the agronomist before the hardware, and forty members are already sending us data from their own monitors."},
    {"id":"narrative-agri-senior-10","level":"senior","profession":"agriculture","title":"Answering the fear behind the contract","scenario":"The food company wants local oats but keeps stalling on your three-year contract proposal. Their unspoken objection isn't price — it's whether one farm can be trusted to deliver every year. Until you address supply risk head-on, no discount will move them.","task":"Write the 3-4 sentences that name their real fear and answer it with structure.","tips":["Say their fear out loud before they do — 'your risk is a short crop on one farm.'","Answer with mechanism: the buffer acres, the backup grower agreement, the shortfall clause.","Naming the unspoken objection is the trust move; it shows you're negotiating for both sides' problem."],"focus":["audience","structure"],"placeholder":"Let me name the thing that would keep me up at night in your chair: one farm, one weather system, and your production line waiting on my oats. So the contract builds in the answer — I plant 15% over the commitment, and the shortfall clause names the two neighboring growers who backstop me at the same spec."},
    {"id":"narrative-agri-senior-11","level":"senior","profession":"agriculture","title":"Cover crops in his arithmetic","scenario":"Your neighbor thinks your cover crops are a subsidy hobby — 'green paint,' he calls it. He farms sharp and respects one thing: the arithmetic. Converting him means dropping the stewardship language entirely and telling the story in dollars per acre on ground like his.","task":"Write the 2-3 sentence case in his frame: costs, returns, and the one field he can check.","tips":["His frame is margin, so start there: seed cost against the input savings and yield hold.","One checkable claim beats five earnest ones: name the field and invite him to watch it.","Skip the virtue words — 'soil health' closes his ears; 'thirty pounds less nitrogen' opens them."],"focus":["audience","precision"],"placeholder":"Costs me $22 an acre in rye seed; buys back thirty pounds of nitrogen and held my beans within a bushel of yours through August when the moisture quit. Watch the field across from your bin site next summer and run your own numbers."},
    {"id":"narrative-agri-senior-12","level":"senior","profession":"agriculture","title":"The wait line, made human","scenario":"Your dryer proposal cites 'average harvest wait times of 2.1 hours.' Accurate, inert. Every director has personally sat in that line — the data just needs a face and a clock. One named evening would move the room more than the season average.","task":"Rewrite the data as a story the directors lived, then land the number on top of it.","tips":["Pick the night they all remember — the last Friday of October, eleven trucks deep.","Attach the cost to the story: combines parked, corn standing in the forecast.","Then the statistic arrives as confirmation, not as the argument."],"focus":["impact","audience"],"placeholder":"The last Friday of October, eleven trucks sat in our yard at 7 p.m. — some of you were in them — while combines idled and rain sat in the forecast. That night wasn't rare: members averaged 2.1 hours a load all fall, and every hour was harvest we made them spend in a cab going nowhere."},
    {"id":"narrative-agri-senior-13","level":"senior","profession":"agriculture","title":"The equity path, pictured","scenario":"Your farm-manager candidate has a bigger salary offer from the corporate operation. Your card to play is ownership — a path from wage to equity that ends somewhere the corporate job structurally can't go. Vague promises of 'a future here' lose to a signing bonus; a pictured decade might not.","task":"Write the 3-4 sentence pitch that walks him from year one to year ten in concrete steps.","tips":["Make each rung specific: profit share at year two, cow herd ownership at five, land at eight.","Contrast the destinations honestly: their ceiling is plant manager; yours is his name on an operation.","Put the first step in writing before he leaves the table — narrative needs a signature to be believed."],"focus":["impact","structure"],"placeholder":"Here's the ten-year picture, and I'll put it in writing: profit share starting year two, your own cows in the herd by year five, and first option on the Hendricks quarter when I retire in eight. Their offer ends at plant manager; this one ends with your name on a farm."},
    {"id":"narrative-agri-senior-14","level":"senior","profession":"agriculture","title":"The window that closes","scenario":"Your family is split on the solar lease — good money, but 'that's farmland' runs deep. What nobody's weighing is that the substation capacity the developer needs is nearly subscribed; the offer expires with it. Urgency without pressure: the deadline is real and needs to be felt, not brandished.","task":"Write the 3-4 sentences that make the closing window concrete without bullying anyone.","tips":["Ground the deadline in its mechanism — substation capacity — so it's a fact, not a tactic.","Frame the decision as choosing between two futures, both named fairly.","Give the family a decision date with room to say no; pressured yeses unravel."],"focus":["impact","clarity"],"placeholder":"The deadline isn't the developer being pushy — the substation has capacity for two more projects, and three are in the queue. If we pass, that's a fair choice, but let's make it as a choice: $48,000 a year on the worst 90 acres we farm, or farming them at a $6,000 loss. I'd like our answer by the 15th."},
    {"id":"narrative-agri-senior-15","level":"senior","profession":"agriculture","title":"Shared water, shared story","scenario":"Your drainage-district petition needs votes from townspeople who see it as farmers' ditches on the public dime. The flood two Aprils ago closed the school for a week and put three feet of water in the hardware store's basement — the same water that drowned your beans. That's the story that makes it one district.","task":"Write the 3-4 sentence narrative that binds town and farm into one before/after.","tips":["Open with THEIR flood memory, not your field loss.","One system, one fix: the water that fills basements is the water that drowns crops.","The after: name what stays dry, on Main Street and in the sections, for what cost per household."],"focus":["audience","impact"],"placeholder":"Two Aprils ago the school closed for a week and the hardware store pumped three feet of water out of its basement — the same water that sat on four thousand acres of crops. It's one watershed, and it fails everybody in it. The district fixes the whole system for about $40 a household a year, and that April doesn't happen again."},
    {"id":"narrative-agri-senior-16","level":"senior","profession":"agriculture","title":"A villain that isn't a person","scenario":"Your case for restructuring the family partnership keeps stalling because every draft reads as an indictment of your brother's management of the cattle side. He'll fight a story where he's the villain — anyone would. The numbers don't need a culprit; they need a common enemy.","task":"Rewrite the framing: the problem named as a structure, not a person, with both of you against it.","tips":["Make the villain impersonal: the entity structure, the market shift, the interest rates.","Put yourselves on the same side of the table facing it: 'the structure is costing us both.'","Check every sentence: could he read it aloud without wincing? That's the test."],"focus":["audience","structure"],"placeholder":"The villain here isn't how either of us runs our side — it's a partnership structure built for 1998 taxes and 1998 prices. It's costing the cattle side and the grain side about $60,000 a year combined, and I want us on the same side of the table against it."},
    {"id":"narrative-agri-senior-17","level":"senior","profession":"agriculture","title":"Why join, for the one who left","scenario":"Young operators buy inputs online and haul to the shuttle loader; your co-op membership pitch about 'cooperative values' bounces off them entirely. The one who listens is the one who hears his own story: alone against retailers sized to ignore him — versus owning a piece of something sized to matter.","task":"Write the 3-4 sentence pitch for a 28-year-old, framed as his before/after, ending with a number.","tips":["His 'before' is real and worth naming: better prices online, sometimes.","The 'after' is leverage and a check: an owner's rebate, agronomy that shows up, a market of last resort.","End on his math: what patronage returned per dollar of business this year."],"focus":["audience","impact"],"placeholder":"Right now you're one truck negotiating with companies that wouldn't notice losing you — and some days the online price wins, no argument. Membership doesn't change the price war; it changes whose side the ammunition lands on: this year members got back 4% of everything they spent, as owners, on top of an agronomist who answers the phone in planting season."},
    {"id":"narrative-agri-senior-18","level":"senior","profession":"agriculture","title":"The appeal, sequenced to conclude","scenario":"Your hail-claim appeal has strong evidence in a weak order: a heap of records the reviewer must assemble into a conclusion. Persuasion is sequence — each exhibit should make the next inevitable, ending where the reviewer has only one place left to land.","task":"Write the 4-sentence evidence sequence: each sentence one exhibit, ordered so the conclusion arrives on its own.","tips":["Order for momentum: the yield history, the third-party count, the comparable settlement, then the gap.","Each sentence should raise the question the next one answers.","Don't state the conclusion angrily at the end — by then it should already be the reviewer's own thought."],"focus":["structure","precision"],"placeholder":"Five years of records put this field at 61 bushels an acre, every year within four of that mark. The independent adjuster's stand count after the storm found 22% of plants viable. The Kellerman claim one section north — same storm, same variety — settled at 78% loss. This claim was appraised at 40%, and nothing in the file explains the difference."},
    {"id":"narrative-agri-senior-19","level":"senior","profession":"agriculture","title":"The debt her father drowned in","scenario":"Your wife's resistance to the expansion loan isn't about your numbers — her family lost their farm in the 1980s, and she watched her father age a decade in two years. Answering her fear with spreadsheets is answering a question she isn't asking. The objection deserves to be named with respect and answered on its own terms.","task":"Write the 3-4 sentences that name her real objection and answer the fear, not just the math.","tips":["Name it plainly and gently — the '80s, her father — so she doesn't have to.","Answer the fear's actual content: what's structurally different about this debt and this decade.","Give her real power in the plan: the trigger point where she can pull the cord."],"focus":["audience","impact"],"placeholder":"I know what this loan looks like from your side of the table — you watched debt take your dad's farm and ten years of his life, and I'm not going to argue you out of that with a spreadsheet. So here's what's different, structurally: fixed rate, land at half of appraisal, and a written trigger — if we hit it, we sell the quarter and clear the note, your call as much as mine."},
    {"id":"narrative-agri-senior-20","level":"senior","profession":"agriculture","title":"Arm your banker's story","scenario":"Your loan officer believes in the expansion — but she doesn't vote. She carries it into a committee room you'll never enter and retells it to skeptics you'll never meet. Your final memo shouldn't argue the case to her; it should hand her the exact story and answers she'll need in that room.","task":"Write the 3-4 sentence narrative you want her to repeat, plus the one objection-answer pair she'll need.","tips":["Write for her retelling: one sentence of story, one of numbers, one of protection.","Anticipate her room's toughest question and script the answer she can give without you.","Make her the hero who found a good loan — that's the story that survives committee."],"focus":["audience","structure"],"placeholder":"The story for your committee: a twenty-two-year customer who's outgrown his grain system, not his discipline — the loan adds capacity, the coverage ratio stays above 1.4 even at county-average yields, and the collateral's at 58%. When they ask what happens if corn goes to $3.80, the answer is: it cash-flows at $3.75, and here's the sensitivity table."},
    {"id":"narrative-agri-senior-21","level":"senior","profession":"agriculture","title":"An ending with dignity","scenario":"Your operating partner of thirty years is slowing down — missed applications, a scary moment with the semi — and won't raise retirement himself. The story he fears is decline and dismissal. The persuasive version is the one where stepping back is the capstone of his work, not the failure of it.","task":"Write the 3-4 sentences that open the conversation, framing his exit as an earned next chapter with a real role.","tips":["Open with what's true and honoring: what he built, specifically.","Frame forward: the transition as his final act of building, teaching the next operator.","Keep one concrete role in the picture — advisor, fall harvest, the seed decisions — so 'retire' doesn't mean 'vanish.'"],"focus":["audience","impact"],"placeholder":"Half of everything this operation is, you built — the tile map in your head alone is thirty years of knowledge nobody can buy. I want to talk about the next chapter while we can design it, not after something forces it: you off the semi and the sprayer, but running fall dryer season and teaching Mark the ground the way only you can."},
    {"id":"narrative-agri-senior-22","level":"senior","profession":"agriculture","title":"The counter to the counter-offer","scenario":"Your herdsman — the best you've had — brings you the big dairy's offer: two dollars more an hour. Matching it buys a year until the next offer; guilt buys nothing. What you have that they don't is a story with him in it: scope, standing, and a stake that compounds.","task":"Write the 3-4 sentence stay pitch: concede the wage math, then tell the future they can't offer.","tips":["Concede the two dollars honestly — pretending it's not real kills your credibility.","Your differentiators must be structural: herd decisions, a heifer share that grows, his name on the breeding program.","End with something signed, not something felt — a stake on paper outweighs a raise in the air."],"focus":["impact","audience"],"placeholder":"Their two dollars is real, and I won't pretend the milk check math doesn't matter. What they can't offer is what you'd be here: the breeding program is yours as of this spring, and the heifer share we put on paper this week means every good decision you make builds your herd inside mine. At their place you're a shift; here you're building something with your name on it."},
    {"id":"narrative-agri-senior-23","level":"senior","profession":"agriculture","title":"Stakes the township can see","scenario":"The proposed spring weight limits read as a technical trucking issue, and the township board is drifting toward yes. The stakes need translating: what those eight weeks of restricted hauling actually do to farms, the elevator, and the township's own tax base — in pictures, not tonnage math.","task":"Write the 3-4 sentence stakes statement for the public hearing: local, human, and numbered.","tips":["Translate tonnage into what the room can picture: doubled trips, spring inputs stranded, fertilizer arriving late for planting.","Follow the money to their interests: the elevator's volume is the township's tax base.","Offer the alternative in the same breath — a permit system, your maintenance contribution — so opposing the limit isn't opposing the roads."],"focus":["audience","impact"],"placeholder":"Eight weeks of limits lands in the exact window fertilizer and seed move: every load doubles into two trips on the same roads, or planting waits on the calendar instead of the weather. The elevator those trucks feed pays a fifth of this township's levy. We're not asking you to choose trucks over roads — the permit-and-maintenance proposal in front of you funds the roads better than the limit does."},
    {"id":"narrative-agri-senior-24","level":"senior","profession":"agriculture","title":"What the processor loses","scenario":"The processor is quietly consolidating routes, and yours — twelve farms on forty miles — is on the block. Your letter so far pleads hardship, which processors are built to withstand. The persuasive frame inverts it: what THEY lose when twelve farms with options stop hauling to them.","task":"Write the 3-4 sentence case framed entirely in the processor's interests.","tips":["Their frame: volume security, component quality, replacement cost — not your hardship.","Quantify what walks away: pounds, butterfat averages, the co-packer contract those solids feed.","Name your alternative calmly — the new plant taking sign-ups — as fact, not threat."],"focus":["audience","precision"],"placeholder":"This route ships 38 million pounds a year at a butterfat average two points over your plant-wide number — the solids your co-packer contract runs on. The new Meridian plant is signing farms our size at a forty-cent premium, and four of the twelve on this route have their paperwork. Keeping the route costs you a haul subsidy; losing it costs you the volume your best contract depends on."},
    {"id":"narrative-agri-senior-25","level":"senior","profession":"agriculture","title":"One member, one number","scenario":"Your annual-meeting case for the capital plan has forty slides of justification. The room will remember one story and one number — if you choose them well and have the discipline to cut the rest. The story is the young member the co-op backed at planting; the number is what the plan returns per member.","task":"Write the 3-4 sentence close: the one story, the one number, and the vote you're asking for.","tips":["One story, told with a name (with permission) — specificity is what makes it travel.","One number, repeated once — per-member terms, not millions.","End on the ask, cleanly: what a yes builds, in one sentence."],"focus":["impact","concision"],"placeholder":"In May, when the Hendricks kid's planter broke with rain coming, our shop had him running in nineteen hours — that's what this co-op is for, and it's what the capital plan protects. The whole plan costs the average member $61 a year and returns better than twice that in fees it keeps from rising. Tonight's yes builds the next twenty years of nineteen-hour turnarounds."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-agri-senior-01","level":"senior","profession":"agriculture","title":"Announcing no dividend","scenario":"For the first time in nine years, the board is paying no patronage dividend — the dryer rebuild took the cash. Your newsletter draft spends two paragraphs on the strong fundamentals before the sentence members will hunt for. Burying it reads as hiding it.","task":"Write the announcement's opening 2-3 sentences, hard news first.","tips":["The no-dividend fact goes in sentence one, unhedged.","Then the why, in one sentence with the number.","Reassurance follows the news and must be specific — 'the equity is intact' with the figure."],"focus":["clarity","impact"],"placeholder":"There will be no patronage dividend this year — the board put that $1.1 million into the dryer rebuild instead. Your equity is untouched, and here's exactly what the money bought."},
    {"id":"hard-agri-senior-02","level":"senior","profession":"agriculture","title":"Letting the hired man go","scenario":"Twelve years, and the work has slipped past what warnings can fix: the missed spray window cost real money, the truck incident could have cost more. Tomorrow morning you end it. Your rehearsed opening keeps growing preamble — the weather, the season, his family — before the sentence that matters.","task":"Write the first three sentences of the conversation: the decision, the reason, and what happens next.","tips":["The decision in sentence one — hope dies in every sentence of preamble.","One honest reason, already documented; this isn't the conversation for the full list.","Then the practical care: last day, final pay, the reference you can honestly give."],"focus":["clarity","audience"],"placeholder":"Dave, I'm letting you go, and I want to do this straight with you. The spray window and the truck are the reasons — we've talked about both, and I can't carry the risk anymore. Your last day is Friday; you'll have two months' pay, and I'll tell any operation the truth: twelve mostly good years."},
    {"id":"hard-agri-senior-03","level":"senior","profession":"agriculture","title":"Walking away from the quarter","scenario":"The landlord you've rented from for nineteen years wants a rent that loses you money three years out of five. You're giving notice, and he'll hear it as a verdict on the relationship. Your draft letter is so padded with gratitude the actual notice is nearly invisible.","task":"Write the letter's first two sentences: the notice, plainly, and the honest why.","tips":["The decision first — gratitude that precedes bad news reads as anesthesia.","The reason is arithmetic, not grievance: name the number that doesn't work.","Leave the door open in one genuine sentence, not three."],"focus":["clarity","concision"],"placeholder":"I won't be renewing the lease on the quarter for next year — at $310 an acre, the numbers lose money for me in most years, and I can't farm that way. Nineteen years on your land has been one of the best arrangements of my career, and if the number ever works again, I hope I'm your first call."},
    {"id":"hard-agri-senior-04","level":"senior","profession":"agriculture","title":"The no your son remembers","scenario":"Your son wants the partnership to bid on the auction quarter, and the answer is no — the debt load would sit on the years when he'll be taking over. He'll hear the no as doubt in him. The message has to carry both the refusal and the fact that it isn't one.","task":"Write the 3-4 sentences: the clean no, the real reason, and what you're protecting for him.","tips":["Say no once, completely — a mushy no invites a campaign.","The reason is the balance sheet he inherits, not his readiness; make that distinction out loud.","Give him something real: the criteria under which the next farm is a yes."],"focus":["clarity","impact"],"placeholder":"The answer is no on this one, and I want you to hear the actual reason: at that price, the debt lands on the exact years you'll be taking over, and I won't hand you a farm that owns you. This isn't doubt about you. The next quarter that cash-flows at 60% of appraisal, we bid — together."},
    {"id":"hard-agri-senior-05","level":"senior","profession":"agriculture","title":"Who runs the farm","scenario":"The succession decision is made: your daughter, who stayed and built the dairy side, becomes managing partner — not your son, who assumed the oldest child inherits the chair. Tonight's family meeting is where he learns it. There is no framing that makes this painless; there is a framing that makes it clear and respectful.","task":"Write the announcement: the decision, the reason it was made this way, and what his stake remains.","tips":["Announce the decision without apology — apologizing for a right decision undermines it.","The reason is criteria, not comparison: name what the role required.","His inheritance and voice stay real; say exactly what they are before he has to ask."],"focus":["clarity","structure"],"placeholder":"I've decided Sarah becomes managing partner in January. The decision came down to one criterion: who's run a division at a profit for ten straight years. Tom, your third of the land and your seat on every major decision don't change — and I'd rather you hear the whole reasoning tonight than wonder about it for a decade."},
    {"id":"hard-agri-senior-06","level":"senior","profession":"agriculture","title":"Asking for the rent cut","scenario":"Corn is under breakeven and the lease on the Miller ground is $40 above what the numbers support. You need to ask a good landlord for a reduction — a hard message going up, not down. The draft keeps apologizing; what it needs is the honest arithmetic and a fair proposal.","task":"Write the ask: the situation in one sentence, the number you're proposing, and what you're offering back.","tips":["Lead with the ask and the number — the apology tour helps nobody decide.","Show the arithmetic that makes the current rent impossible, briefly.","Offer something in return: a flex clause when prices recover, the tile you'll still install."],"focus":["clarity","audience"],"placeholder":"I'm asking to reset the rent from $290 to $250 for next year — at current prices, $290 loses me $47 an acre on your ground, and I can show you the budget. In exchange, I'll put a bonus clause in: if December corn tops $5.20, you get half the upside back."},
    {"id":"hard-agri-senior-07","level":"senior","profession":"agriculture","title":"The foreman's temper","scenario":"Your foreman is the most skilled man on the place and this morning he tore into a seasonal kid in front of the whole crew — the third time this season. The kid's packing his things unless you act. Praise-sandwich feedback would blur the one thing that has to be unmistakable.","task":"Write the feedback: the specific behavior, its cost, and the line that can't be crossed again.","tips":["Behavior, not character: what he said, where, in front of whom.","The impact in operation terms: the crew you can't keep, the mistakes fear breeds.","The ask is a boundary with a consequence, stated once, without heat."],"focus":["clarity","impact"],"placeholder":"This morning you dressed Tyler down in front of the whole crew — third time this season, and he's half-packed. You're the best operator I've got, and I can't staff a farm where good kids get burned in public. Correct anyone you need to, in private; the next public one, we're having a different conversation."},
    {"id":"hard-agri-senior-08","level":"senior","profession":"agriculture","title":"Leaving the seed dealer","scenario":"Your seed dealer is a friend of twenty years, and next season your seed order goes elsewhere — his lineup has fallen behind on the traits your ground needs, and the local trials show it. He'll take it as personal. The message can be kind and still has to be final.","task":"Write the 3-4 sentences: the decision, the honest reason, and the friendship set apart from it.","tips":["Decision first, in his driveway or across his counter — not by text.","The reason is the trial data, not his effort; name the numbers so it's not a mood.","Separate the accounts explicitly: the business changes, the friendship doesn't."],"focus":["clarity","audience"],"placeholder":"I'm moving the seed order next year, and I wanted you to hear it from me standing here, not from the delivery schedule. The county trials had your numbers eight bushels back two years running on ground like mine, and I can't farm past that. This is the business deciding, not the friendship — that part doesn't move."},
    {"id":"hard-agri-senior-09","level":"senior","profession":"agriculture","title":"Self-reporting the bad loads","scenario":"Your night hauler mixed bins and delivered three loads of ordinary corn against your food-grade contract before anyone caught it. The buyer's plant may already be running it. Every hour you sit on the news multiplies the damage — to the product and to you.","task":"Write the call script: what happened, what's at risk, what you're doing, in four sentences.","tips":["Lead with what he needs to act on: which loads, which delivery times.","No minimizing — his risk assessment needs the full size of it.","Bring the remedy you're already doing: the hold, the retest, the replacement bushels."],"focus":["clarity","structure"],"placeholder":"Stop unloading anything from us since Tuesday — three of those loads were commodity corn against the food-grade contract, a bin mix-up on our end, tickets 4417 through 4419. I've isolated the rest, retested the true food-grade bin, and I can have replacement loads rolling tomorrow. Tell me what the three loads cost you and it's on my account."},
    {"id":"hard-agri-senior-10","level":"senior","profession":"agriculture","title":"Closing the agronomy department","scenario":"The board voted: the co-op's agronomy department winds down by spring — the regional retailers have taken the volume, and the losses are eating the grain side's margins. Four employees, two of them members' kids, hear it from you tomorrow before any member does.","task":"Write the opening of the staff meeting: the decision, the timeline, and what the co-op will do for them.","tips":["The decision in the first sentence — they'll hear nothing else until it lands anyway.","The reason is numbers they've seen themselves; one sentence, no blame.","Spend the message on what's concrete for them: dates, severance, the calls you'll make."],"focus":["clarity","audience"],"placeholder":"The board voted last night to close the agronomy department by April 1, and I wanted you four to hear it from me before anyone else in the county. The division's lost money three years straight and the board ran out of honest ways to carry it. Here's what's certain this morning: full pay through April, severance at two weeks a year, and I start making calls on your behalf today."},
    {"id":"hard-agri-senior-11","level":"senior","profession":"agriculture","title":"The quote you got wrong","scenario":"You quoted the widow $138 an acre for custom farming her 240 — and forgot her ground needs the second fungicide pass and the long haul to the elevator. The honest number is $155. Eating the difference sets a precedent you can't afford; springing it at settlement would be worse. The call has to happen now.","task":"Write the call: the mistake owned, the corrected number, and her clean way out.","tips":["Name it as your error before she can wonder — 'I quoted wrong, and that's on me.'","The new number with its two reasons, briefly.","Give her a real exit: the survey's other names, no hard feelings — that offer is what keeps the trust."],"focus":["clarity","audience"],"placeholder":"Ruth, I made a mistake on your quote and I'd rather fix it now than surprise you in December. The honest number is $155, not $138 — your ground needs the second fungicide pass and the haul is twice my average. If that changes your mind, I'll give you two good names from the survey myself."},
    {"id":"hard-agri-senior-12","level":"senior","profession":"agriculture","title":"Declining the neighbor's ground","scenario":"Your neighbor finally offered you his 320 — at $75 an acre over what it can earn. Saying yes buys a slow loss; a vague 'let me think on it' strings him along while he could find another tenant. The no needs to come now, clean, and leave the gate open at a real number.","task":"Write the 2-3 sentence decline: the no, the number that would work, and the standing offer.","tips":["Decline the price, not the ground — that's the true distinction, so use it.","Name your workable number so the no has content.","No pressure, no lecture on his expectations; the number speaks."],"focus":["clarity","concision"],"placeholder":"At $340 I have to pass — that's above what the ground can pay me back. At $265 I'd sign for three years tomorrow, and that offer stands whenever you want it."},
    {"id":"hard-agri-senior-13","level":"senior","profession":"agriculture","title":"No bonus this year","scenario":"The crew worked a brutal harvest, and every year for six years there's been a December bonus. This year the farm lost money and there isn't one. They'll hear it eventually from the empty envelope; they should hear it from you now, with the reason and what you can do instead.","task":"Write the 3-4 sentences you'd say at the shop meeting.","tips":["Say it straight: no bonus this year, and the honest number behind it.","Don't dress the loss up or down — they watched the drought too.","Give what's true and real: the wage stays, the jobs are safe, the bonus returns with the margin."],"focus":["clarity","audience"],"placeholder":"There's no bonus this December, and you deserve the straight reason: the farm lost about $140,000 this year and the bonus money doesn't exist. Nobody's job is at risk and nobody's wage is going backward. The year this place makes money again, the bonus comes back first — before any new paint sits in that yard."},
    {"id":"hard-agri-senior-14","level":"senior","profession":"agriculture","title":"The brother conversation","scenario":"The cattle side your brother runs has lost money four of five years, and the grain side has been quietly covering it. He works harder than anyone you know, which is exactly why the conversation keeps not happening. The partnership can't carry another year of silence.","task":"Write the opening 3-4 sentences: the facts, the distinction between effort and results, and the ask.","tips":["Open with the number and how long — vagueness would insult you both.","Separate the man from the P&L out loud: the effort's never been the question.","The ask is a joint review with real options on the table, not a verdict already reached."],"focus":["clarity","structure"],"placeholder":"The cattle side has lost money four of the last five years — about $180,000 total — and the grain side's been covering it, which neither of us has said out loud. Nobody works harder than you, and that's exactly why this is hard to say: effort isn't the problem, the economics are. I want us to sit down with the numbers in January and put every option on the table, including ones I won't like either."},
    {"id":"hard-agri-senior-15","level":"senior","profession":"agriculture","title":"Closing the farm stand","scenario":"Thirty years of Saturday customers, and the farm stand loses money every season your daughter-in-law no longer has time to run it. The sign on the door matters less than the note to the email list — loyal people deserve the news straight, with the gratitude real and the reason honest.","task":"Write the customer note: the closing, the reason, the thanks, and where to find you.","tips":["The closing and the date first — nostalgia after the news, not before.","One honest sentence of reason; customers can smell a fudge.","End with what continues: the locker beef, the farmers market booth, the wave from the road."],"focus":["clarity","audience"],"placeholder":"The stand won't open this June — after thirty years, we're closing it for the plainest reason there is: it stopped paying for the hours it takes, and the person whose hours they were needs them back. You made Saturday mornings the best part of this farm. Our beef is still at the locker in town, and we'll see you at the county market, first table on the left."},
    {"id":"hard-agri-senior-16","level":"senior","profession":"agriculture","title":"Firing the custom applicator","scenario":"Third season, third drift complaint — this one onto the certified-organic farm north of the field, which could cost that neighbor his certification. Your custom applicator is apologetic, likeable, and cheaper than anyone. The relationship ends today, in writing, because the next incident lands in court.","task":"Write the termination note: the decision, the documented pattern, and the boundary on future work.","tips":["Decision first; the pattern second, with dates — this note may be read by lawyers someday.","No character verdicts — just the incidents and the exposure you can't carry.","Close the door completely; 'maybe next season' restarts the risk."],"focus":["clarity","precision"],"placeholder":"Effective today, we won't be using your application services — this ends the arrangement entirely, not just for the season. Three drift incidents in three seasons — June 2024, May 2025, and the Hendricks organic parcel two weeks ago — is a pattern I can't carry liability for. I'll pay the outstanding invoice in full this week."},
    {"id":"hard-agri-senior-17","level":"senior","profession":"agriculture","title":"Writing up your best man","scenario":"Your most reliable employee — fifteen years, never a problem — cleared a plugged auger yesterday without locking out, with the new kid watching. The lockout rule went in after the last near-miss, and it has no seniority clause. The write-up must land without torching the loyalty.","task":"Write what you'd say handing him the write-up: the violation, why the paper matters, and the respect kept intact.","tips":["Name the act and the rule — his standing is exactly why it can't slide.","The new kid watching IS the impact; say it.","Respect and the write-up coexist: this is the rule working, not doubt about him."],"focus":["clarity","impact"],"placeholder":"This is a written warning for clearing the auger without lockout yesterday — the same paper anyone on this place would get, which is the point. Tyler was watching, and what you do is the training manual around here whether you like it or not. Fifteen years of trust is exactly why I can't let the best man on the farm teach the wrong lesson."},
    {"id":"hard-agri-senior-18","level":"senior","profession":"agriculture","title":"The fee increase letter","scenario":"Drying fees go up 15% this fall — the propane contract and the dryer debt leave no choice. The draft letter to members spends four paragraphs on natural-gas markets before the number. Members will forgive an increase explained straight; they won't forgive feeling managed.","task":"Write the letter's opening: the increase and effective date first, then the one-sentence reason.","tips":["The number and the date in sentence one — hunting for it breeds resentment.","One honest reason with a number in it, not a market essay.","Then what you held flat, if true — that's the credibility line."],"focus":["clarity","concision"],"placeholder":"Drying fees increase 15% on September 1 — from 4.5 to 5.2 cents a point. Propane is contracted 22% higher than last fall, and the dryer note payments start this year; those two facts are the whole story. Storage and handling rates stay where they were."},
    {"id":"hard-agri-senior-19","level":"senior","profession":"agriculture","title":"Disputing the vet bill","scenario":"The invoice for the herd workup is $2,300 over the estimate, with no call when it ran long. You need this vet — she's the best in three counties — and you need to not pay for surprise as a habit. The message must hold both: the dispute and the relationship.","task":"Write the note: what you're paying now, what you're disputing, and the arrangement you want going forward.","tips":["Pay the undisputed part immediately and say so — it proves this is about process, not money.","Dispute the specific line with the specific reason: no call past the estimate.","The forward ask is the real point: a call at 110% of estimate, every time."],"focus":["clarity","structure"],"placeholder":"I've paid the $4,100 that matches the estimate today. I'm asking you to look again at the $2,300 above it — a heads-up call when the workup ran long would have let me make that call, and that's the arrangement I want from here: anything tracking past 110% of estimate, my phone rings before the work continues. You're the best vet in three counties, which is why I'm writing instead of switching."},
    {"id":"hard-agri-senior-20","level":"senior","profession":"agriculture","title":"Unwinding the handshake","scenario":"In March you shook hands on buying Carl's 160 come fall — no paper, his word and yours. Since then, rates moved, your hail claim settled low, and the deal no longer works. In this county your handshake is your balance sheet. The retraction has to be fast, in person, and complete.","task":"Write what you'd say in his kitchen: the retraction, the ownership of it, and what you'll do to make it right.","tips":["Say it whole in the first sentence — a retraction that dribbles out is worse.","Own it as your word broken, not the market's fault — even though it's both.","Offer the make-right: cover his relisting costs, waive nothing, expect nothing."],"focus":["clarity","impact"],"placeholder":"Carl, I'm here to tell you I can't honor the handshake on the 160, and I know exactly what that sentence costs me in your kitchen. The hail settlement and the rates broke it, but the word was mine and it's mine breaking. Whatever the fall listing costs you — appraisal, auction fees — send me the bill, and if you never deal with me again, I'll understand it."},
    {"id":"hard-agri-senior-21","level":"senior","profession":"agriculture","title":"The nephew's assumption","scenario":"Your nephew has hinted for years that the west 80 'stays in the family' — meaning him. The estate plan sells it to fund your wife's care. He's built plans on an inheritance nobody promised, and the longer the assumption lives, the more it costs him. Kindness here is early clarity.","task":"Write the conversation opener: the fact, the reason, and what you can honestly offer instead.","tips":["Correct the assumption directly — softening it just re-plants it.","The reason — funding care — needs no apology; say it with its dignity intact.","Offer what's real: first option to buy at appraisal, or nothing, but never a new hint."],"focus":["clarity","audience"],"placeholder":"Jake, before another season goes by planning around it: the west 80 gets sold when I'm gone — it funds Marie's care, and that was decided with a clear head. Nobody ever promised it to you, but I know the hoping was real, and I'm sorry the hoping and the plan never matched. What I can offer is first option to buy it at appraisal, and that one I'll put in writing."},
    {"id":"hard-agri-senior-22","level":"senior","profession":"agriculture","title":"Withholding the endorsement","scenario":"A member you've known forty years asks you — as outgoing president — to endorse him for the board. He'd be a poor director: he treats every disagreement as betrayal and every meeting as a stage. He's also asked you directly, face to face, which forecloses the quiet dodge.","task":"Write the spoken answer: the no, delivered with respect, without a character indictment.","tips":["The no must be findable in your first two sentences — a foggy blessing is a lie he'll repeat.","Give a reason that's true and survivable: your endorsement standard, not his portrait.","Offer what's honest: your respect, stated plainly, without the signature."],"focus":["clarity","audience"]},
    {"id":"hard-agri-senior-23","level":"senior","profession":"agriculture","title":"The third milker","scenario":"Selling forty cows to fix the debt ratio means two milkers can cover the parlor, and Elena — last hired, hardest worker in the barn — loses her job. The herd decision was right and doesn't make this morning easier. She deserves the news first, straight, and with everything you can actually do.","task":"Write the conversation: the decision, the true reason, and the concrete help.","tips":["Lead with the decision and that it's about herd size, not her work — in the same breath.","Don't let the compliment soften the fact; let it be true alongside it.","The help must be booked, not vague: the calls you'll make, the reference, the timeline."],"focus":["clarity","audience"],"placeholder":"Elena, we sold forty cows and the parlor only needs two milkers now — I'm eliminating the third position, which is yours because you're newest, not because you're anything but the hardest worker in that barn. You have four weeks and I'll pay a fifth. I already called the Vander Wal dairy this morning; they want to meet you Thursday, and my reference will be the easiest one I've ever given."},
    {"id":"hard-agri-senior-24","level":"senior","profession":"agriculture","title":"Six months in, not working","scenario":"The farm manager you hired with such hope is six months in and it isn't working — good agronomy, but the crew is fraying under him and two longtime hands have quietly asked about winter work elsewhere. The conversation is a fork: a real improvement plan or a parting, decided in thirty days either way.","task":"Write the opening: the honest assessment, the two paths, and the thirty-day terms.","tips":["Name both truths: what's working and what's failing — specifics, not vibes.","The fork must be real: measurable change by a date, or a clean, funded exit.","Say what you'll do differently too; six-month failures are rarely one person's."],"focus":["clarity","structure"],"placeholder":"Six months in, here's my honest read: your agronomy is the best this farm has had, and the crew is coming apart underneath you — two of my longest hands are looking at the door. That's a fork, not a firing: thirty days, and the specific change is that scheduling and corrections run through the Monday meeting, not the radio. If it works, this job is yours for years; if it doesn't, we part with a full quarter's pay and I'll own my share of the miss."},
    {"id":"hard-agri-senior-25","level":"senior","profession":"agriculture","title":"The loss, then the ledge","scenario":"The hailstorm took the co-owned farm's entire corn crop — your sisters wake up to the news today. The loss headline can't be softened, but a bare loss headline breeds panic in owners who live two states from the nearest field. The message needs both: the plain fact and the solid ledge under it.","task":"Write the text you'd send both sisters this morning: the loss, the insurance floor, and the next step.","tips":["The whole loss in the first sentence — partial reveals mean three worse phone calls.","The ledge is a number: what insurance guarantees per acre, when it pays.","One next step with a date keeps the worry pointed somewhere useful."],"focus":["clarity","concision"],"placeholder":"Hard news this morning: last night's hail took the corn on the home place — all of it, no replant window left. The floor under us: revenue protection guarantees about $580 an acre, which covers costs and your land payment, with the claim filed within the hour. I'll call you both Sunday at 7 with the adjuster's timeline."}
  ],
  "putting-it-together": [
    {"id":"together-agri-senior-01","level":"senior","profession":"agriculture","title":"The full loan memo","scenario":"The bank wants a one-page memo before Thursday's committee: the $900,000 grain-system loan, in your words. It needs everything at once — the ask up front, a structure the committee can follow, numbers that survive a skeptic, and a close that tells them what to do.","task":"Write the full memo, 6-8 sentences: ask, three supports, risk handling, and the decision requested.","tips":["Sentence one carries the ask, the number, and the payback.","Three supports, each with a figure: capacity, income, protection.","Close on the specific decision and date you need."],"focus":["structure","impact"],"placeholder":"I'm requesting $900,000 over ten years for a grain-handling system that pays for itself in seven. Three things carry the case:"},
    {"id":"together-agri-senior-02","level":"senior","profession":"agriculture","title":"One storm, three audiences","scenario":"The hail took 60% of the crop. Before sundown, three messages leave your desk: one to the banker, one to the landlords, one to the family group chat. Same facts — but the banker needs coverage math, the landlords need stewardship assurance, and the family needs steadiness.","task":"Write the one core sentence for each of the three audiences, showing how the same fact shifts.","tips":["Banker: the loss AND the insurance floor against the payments, in one sentence.","Landlords: their land's crop, the claim filed, rent unaffected.","Family: the plain truth plus the calm — nobody's livelihood just left."],"focus":["audience","clarity"],"placeholder":"To the bank: hail took 60% yesterday, and revenue protection floors us above debt service — the renewal plan doesn't change. To the landlords:"},
    {"id":"together-agri-senior-03","level":"senior","profession":"agriculture","title":"The crisis update, complete","scenario":"The fertilizer plant fire is four hours old: contained, nobody hurt, anhydrous tanks safe but the blender building gone, spring season six weeks away. Members, staff, and the fire marshal all need word. Your member update has to do everything at once — lead, structure, precision, calm.","task":"Write the full 5-6 sentence member update integrating every skill.","tips":["First sentence: nobody hurt, fire contained — the two facts every reader needs first.","Fixed structure: what happened, what's safe, what it means for spring, next update.","Numbers and dates, no adjectives doing the reassuring."],"focus":["structure","precision"],"placeholder":"Nobody was hurt in this morning's fire at the plant, and it was contained by 9 a.m. What burned: the blender building. What didn't: every anhydrous tank, the warehouse, and your prepaid product."},
    {"id":"together-agri-senior-04","level":"senior","profession":"agriculture","title":"The annual address, whole","scenario":"Fifteen minutes, two hundred members, and a year that held a fee increase, a record grain volume, and the dryer decision. The address needs a governing message, three signposted sections, real numbers, and a close that lands — the whole toolkit in one speech.","task":"Write the opening 5-6 sentences: governing message, the spoken map, and the first section's headline number.","tips":["One sentence the sleepiest member takes home — write it first.","Say the map out loud: 'the year, the money, the dryer.'","First section opens with its number, not its narrative."],"focus":["structure","impact"],"placeholder":"One message tonight: your co-op earned its keep this year, and the numbers prove it. Three things — the year, the money, and the dryer decision everyone's been asking about."},
    {"id":"together-agri-senior-05","level":"senior","profession":"agriculture","title":"The succession letter, entire","scenario":"You're writing the letter that accompanies the signed succession documents to all three children — the one they'll reread for years. It has to lead with the decision, structure the who-gets-what plainly, keep fair and equal distinct, pre-empt the obvious hurt, and end on the family.","task":"Write the full letter, 7-8 sentences, integrating lead, structure, precision, and care.","tips":["The plan's headline in sentence one — they've waited years for it.","Three labeled parts: the farm's operation, the land, the money.","Name the fair-versus-equal distinction yourself, before they feel it unnamed."],"focus":["structure","audience"],"placeholder":"The papers with this letter do what I told you they would: Mark runs the farm, all three of you own it, and the plan is built to outlive my explanations of it."},
    {"id":"together-agri-senior-06","level":"senior","profession":"agriculture","title":"Ninety seconds, everything on","scenario":"The state water board gives you ninety seconds on the allocation rule. In that window: a position stated first, one piece of checkable evidence, one human stake, and a specific ask — with a register that respects the podium and the clock.","task":"Write the full 90-second testimony, roughly 110 words.","tips":["Position and ask in the first two sentences; the clock eats closers.","One number with a named source; one farm-level consequence.","End by repeating the ask in different words — it's what the minutes record."],"focus":["concision","impact"],"placeholder":"I'm Ray Kowalski, I farm 900 irrigated acres in this district, and I'm asking the board to amend section 4 to phase the cuts over three years instead of one."},
    {"id":"together-agri-senior-07","level":"senior","profession":"agriculture","title":"The renewal package, framed","scenario":"Your annual loan renewal package goes in Friday: statements, projections, insurance summaries. The cover memo is what the committee reads first and the analyst reads last. One page to lead with the state of the operation, structure the exhibits, and flag the one soft spot before they find it.","task":"Write the cover memo, 5-6 sentences: headline, the map of what's enclosed, and the self-flagged weakness.","tips":["Open with the sentence they'd write themselves if all went well: covenants met, payments current.","Map the package so the analyst never hunts.","Flag your own soft spot with its mitigation — found-by-you beats found-by-them."],"focus":["structure","precision"],"placeholder":"The operation enters renewal with every covenant met and payments current for the twenty-third consecutive year. Enclosed, in order: the balance sheet, three-year cash flow, and the insurance schedule. One number to flag before you find it —"},
    {"id":"together-agri-senior-08","level":"senior","profession":"agriculture","title":"Run the checklist","scenario":"Your draft letter to the county board about the road project is due in an hour: 500 words, opens with township history, the ask appears in paragraph four, 'significant impact' appears three times, and it never says what you want the board to actually do. Run the full pre-send checklist against it.","task":"Name what fails each checklist question — point first? one idea? a third cuttable? vague claims? position taken? — and write the corrected opening 2 sentences.","tips":["Audit before rewriting: name each failure specifically.","The corrected opening carries the ask and one number.","The checklist is the product here — practice the diagnosis, not just the cure."],"focus":["structure","concision"],"placeholder":"Fails: the ask hides in paragraph four; 'significant impact' carries no number; half the history can go. Corrected opening: I'm asking the board to approve the culvert replacement on 310th Street before spring —"},
    {"id":"together-agri-senior-09","level":"senior","profession":"agriculture","title":"The first sixty seconds","scenario":"The annual price sit-down with your processor starts in an hour. Your opening sixty seconds sets the frame for everything after: your headline ask, the two numbers that carry it, the concession you're ready to trade, and a tone that says partner, not supplicant.","task":"Write the spoken opening, 4-5 sentences, integrating lead, precision, and presence.","tips":["The ask first, at full strength — openings negotiated down from strength, never up from apology.","Two numbers maximum; the rest wait in the folder.","Name what you're ready to give — it signals a deal, not a demand."],"focus":["impact","structure"],"placeholder":"I'm here for a forty-cent increase on the base, and I'll show you the two numbers that justify it in a minute. I'm also bringing something: flexibility on delivery windows you've been wanting for two years."},
    {"id":"together-agri-senior-10","level":"senior","profession":"agriculture","title":"The speech before the ballot","scenario":"In two minutes, members vote on the merger. You get the last word: the case in miniature, the strongest objection honored, your position owned, and the room released to decide. Everything the year taught you, in two minutes at a wooden podium.","task":"Write the full two-minute speech, roughly 150 words.","tips":["Open on your position — the room has waited a year for the plain version.","Give the opposition its best sentence, honestly, then answer it.","End with the vote framed as the members' power, not your victory."],"focus":["impact","audience"],"placeholder":"I'm voting yes tonight, and here's the whole case in one sentence: alone, our volume shrinks every year, and merged, we bid against the majors with the branch doors open."},
    {"id":"together-agri-senior-11","level":"senior","profession":"agriculture","title":"The apology that holds","scenario":"Your sprayer drifted onto the neighbor's certified-organic field — the field that anchors his certification and his premium contracts. The message you send today will be forwarded to his certifier and maybe his lawyer. It needs the fact, the ownership, the remedy, and no weasel — all at once.","task":"Write the full message, 5-6 sentences: what happened, plain ownership, the concrete remedy, next steps.","tips":["State the drift as fact — 'may have' language voids the apology and inflames the lawyer.","Remedy in numbers: the testing you'll fund, the losses you'll cover, the setback you'll plant.","One sentence of relationship, at the end, where it's true instead of tactical."],"focus":["clarity","impact"],"placeholder":"On Tuesday morning my sprayer drifted onto the north edge of your organic field — my operator's error, in wind we shouldn't have run in, and I'm not going to soften any of that. Here's what I'm doing about it: residue testing at my cost this week, at your certifier's lab, their choice."},
    {"id":"together-agri-senior-12","level":"senior","profession":"agriculture","title":"The offer letter, complete","scenario":"Your chosen farm-manager candidate is deciding between you and the corporate operation this weekend. The offer letter is your closing argument: the offer led plainly, the equity path structured, the numbers precise, and the warmth real — one page that reads like the operation he'd be joining.","task":"Write the full offer letter, 6-7 sentences.","tips":["The offer — title, salary, start date — in sentence one.","The equity path in dated, numbered steps; that's your differentiator, so give it structure.","Close with the deadline and the welcome, both genuine."],"focus":["structure","audience"],"placeholder":"The job is yours: farm manager, $72,000, housing included, starting March 1 if you'll have it. Beyond the salary, here's the path we talked about, now in writing —"},
    {"id":"together-agri-senior-13","level":"senior","profession":"agriculture","title":"The summary the reviewer scores","scenario":"The rural-development grant gives you 200 words of project summary — the paragraph the reviewer scores before deciding whether to read the rest. Jobs, dollars, feasibility, community: every claim precise, every sentence pulling, the grandmother's recipe earning exactly one clause.","task":"Write the full 200-word summary integrating precision, structure, and audience.","tips":["First sentence: what gets built, what it costs, what it returns — the reviewer's whole rubric in miniature.","Every claim numbered: jobs, wages, local purchases, timeline.","The heart gets one clause, placed where it warms instead of pads."],"focus":["precision","audience"],"placeholder":"This project converts an existing dairy barn into a licensed creamery producing bottled milk and butter — $410,000 total cost, 4 full-time jobs at $22-28/hour within twelve months, and $180,000 a year in milk purchased from three neighboring farms."},
    {"id":"together-agri-senior-14","level":"senior","profession":"agriculture","title":"The landlord letter, whole","scenario":"The year-end letter to your best landlord carries everything this course teaches: results led with numbers, her stake framed first, structure she can skim, the rent conversation deferred to its own meeting, and warmth that's real. One page, once a year, compounding for a decade.","task":"Write the full letter, 6-8 sentences.","tips":["Open with her farm's performance — the sentence she reads aloud to her husband.","Three skimmable parts: results, what you invested in her land, next year's plan.","Name the rent meeting for January rather than burying the topic — clarity beats ambush both ways."],"focus":["audience","structure"],"placeholder":"Your farm had the best year on my books: 214-bushel corn on the east field, and I put $41 an acre back into the ground it grew on."},
    {"id":"together-agri-senior-15","level":"senior","profession":"agriculture","title":"The hardest renewal","scenario":"This year's renewal meeting follows the loss: $140,000 down, one covenant tripped, and a plan you believe in. Your opening five sentences must lead with the truth, structure the meeting, show the fixed numbers, and sound like a man worth renewing — presence and precision under the worst light.","task":"Write the spoken opening, 5 sentences, integrating everything.","tips":["Say the loss and the tripped covenant before she does — first-mover honesty is the whole game.","Then the map: what caused it, what's changed, what you're asking.","The changed things need numbers and dates, not resolve."],"focus":["clarity","impact"],"placeholder":"Let's start with the worst of it, from me: the farm lost $140,000 and tripped the working-capital covenant, and you shouldn't hear that anywhere but from this chair. The next twenty minutes: what caused it, the three things already changed, and the one adjustment I'm asking for."},
    {"id":"together-agri-senior-16","level":"senior","profession":"agriculture","title":"The statement at the fence line","scenario":"The manure spill reached the county drainage ditch, the cleanup contractor is on site, and the TV truck is at the end of your driveway. Your statement must lead with what happened and what's being done, stay inside the confirmed facts, take ownership without admitting what lawyers haven't reviewed, and give the next update time.","task":"Write the full on-camera statement, 5-6 sentences.","tips":["Confirmed facts first: what spilled, when contained, who's on site.","Ownership of the response is safe ground: 'my crew found it, my call brought the contractor.'","Name the next update and keep it — the second statement is where trust is won."],"focus":["precision","audience"],"placeholder":"Yesterday evening a transfer line failed and manure reached the drainage ditch; my crew found it at six, had it contained by eight, and the cleanup contractor has been on site since daylight. The state was notified within the hour, and their inspector is standing a hundred feet from me now."},
    {"id":"together-agri-senior-17","level":"senior","profession":"agriculture","title":"Opening the estate meeting","scenario":"All three kids, two spouses, your wife, and the lawyer on speakerphone: the meeting where the plan becomes real. Your opening must state the decision, map the ninety minutes, set the register — decided but not defensive — and make the first hard thing sayable before the coffee's cold.","task":"Write the full opening, 5-6 sentences: decision, map, ground rules, and the invitation to push.","tips":["The plan's one-sentence version first — everyone's been guessing for months.","Map the meeting so nobody fights the agenda instead of the substance.","Invite the hardest question yourself; naming the elephant is the chair's job."],"focus":["structure","audience"],"placeholder":"Here's the plan in one sentence, and then we'll spend ninety minutes on it: Mark runs the operation starting next year, all three of you inherit the land equally, and the buyout terms protect both facts. Tonight has three parts."},
    {"id":"together-agri-senior-18","level":"senior","profession":"agriculture","title":"The fee letter that keeps members","scenario":"The 15% drying-fee increase letter is really a retention letter: the shuttle loader's flyer is on every member's counter. It must lead with the number, explain with real figures, frame what membership still returns, and close without begging — the whole course in 150 words.","task":"Write the full letter, 6-7 sentences.","tips":["Increase, date, and new rate in the first sentence.","The honest why in numbers members can check: the propane contract, the dryer note.","The membership math — patronage against the fee difference — is your close; run it for them."],"focus":["clarity","audience"],"placeholder":"On September 1, drying goes from 4.5 to 5.2 cents a point — a 15% increase, and here is exactly why. Propane contracted 22% higher, and the new dryer's first note payment lands this fall."},
    {"id":"together-agri-senior-19","level":"senior","profession":"agriculture","title":"The one-page year","scenario":"Every January you write the family's one-page farm plan: last year in three numbers, this year's plan in three decisions, and the one risk that could break it. The discipline of one page IS the communication skill — everything the operation knows, structured until it fits.","task":"Write the full one-pager, 7-8 sentences.","tips":["Three numbers for the year past — chosen, not comprehensive.","Three decisions for the year ahead, each with its date and owner.","One risk, named with its trigger and response — not a worry list."],"focus":["structure","concision"],"placeholder":"Last year in three numbers: net $118,000, corn at 209 against a 214 five-year average, and debt down $160,000. This year, three decisions:"},
    {"id":"together-agri-senior-20","level":"senior","profession":"agriculture","title":"The retirement announcement","scenario":"After the family knows, the crew, the landlords, and the county need the news in the right order and register: the date certain, Mark's takeover framed as continuity, every lease and job explicitly safe, and forty years compressed into one sentence of thanks that doesn't wobble.","task":"Write the announcement, 5-6 sentences, in the version that goes to your landlords and business partners.","tips":["The date and the successor in sentence one — the rest is landing gear.","Each reader's stake answered before asked: leases honored, terms unchanged, same phone number.","One sentence of gratitude, specific enough to be yours."],"focus":["clarity","audience"],"placeholder":"On March 1, 2028, I'm stepping back from daily operations, and Mark — who's run planting and marketing beside me for fifteen years — takes over the operation whole. Every lease, every term, every handshake carries forward exactly as written."},
    {"id":"together-agri-senior-21","level":"senior","profession":"agriculture","title":"The final appeal","scenario":"This is the last letter the insurance company reads before your hail claim goes to arbitration: the dispute stated in the first sentence, the evidence sequenced to conclude, the numbers exact, the tone of a man who'd rather settle and is ready not to. One page, no heat, full weight.","task":"Write the full appeal letter, 6-7 sentences.","tips":["Claim number, disputed amount, and your supported figure in sentence one.","Evidence in escalating order, one sentence each, sources named.","Close with the settlement path and the arbitration date filed — both, without bluster."],"focus":["precision","structure"],"placeholder":"On claim 4471, I dispute the $61,000 appraisal and this letter documents support for $89,000. The evidence, in order: five years of APH records placing the field at 61 bushels;"},
    {"id":"together-agri-senior-22","level":"senior","profession":"agriculture","title":"Four messages, four channels","scenario":"Tonight's list: tell the banker the covenant question is resolved, tell a landlord you're not renewing, remind the crew about the safety meeting, and answer your daughter's hard question about the will. Four messages — and choosing the channel is as much of the skill as the words.","task":"For each message, name the channel — call, visit, letter, or text — and justify each in one sentence.","tips":["Channel follows weight and permanence: hard-and-personal gets a visit, contractual gets paper.","The crew reminder is the only text on the list — instant and low-stakes.","Anything you'd want reread later — or provable later — goes in writing."],"focus":["audience","structure"],"placeholder":"The banker gets a call today — good news travels fastest by voice and she can note the file. The landlord gets a visit, then a confirming letter: the ending deserves a face, the record needs paper."},
    {"id":"together-agri-senior-23","level":"senior","profession":"agriculture","title":"Two minutes with the regional president","scenario":"At the bank's customer field day, you find yourself walking a plot row with the regional president — the man whose signature sits above your loan committee. Two minutes, unplanned, to leave the impression that makes next spring's expansion request land on a warm desk.","task":"Write the two-minute version of your operation and ambition, spoken register, roughly 120 words.","tips":["Lead with the operation in one sentence a banker respects: acres, tenure, record.","The middle is your direction: the constraint you're solving and the ask that's coming.","End with a specific, easy next step — the tour invitation he can delegate."],"focus":["concision","impact"]},
    {"id":"together-agri-senior-24","level":"senior","profession":"agriculture","title":"The keys, handed over","scenario":"The morning the papers take effect, you're saying two hundred words to the family and crew in the farmyard — the speech that turns a legal transfer into a felt one. It needs a point stated first, one story doing the work of forty years, and an ending that hands the future over cleanly.","task":"Write the full 200-word speech.","tips":["Say the headline plainly: as of this morning, it's Mark's operation.","One story, chosen for what it teaches, not what it flatters.","End facing forward — the last sentence belongs to the farm's future, not your past."],"focus":["impact","audience"],"placeholder":"As of seven o'clock this morning, this operation belongs to Mark — signed, filed, and right. Before everybody scatters to work, one story."},
    {"id":"together-agri-senior-25","level":"senior","profession":"agriculture","title":"The message on your desk tonight","scenario":"Every operation has one: the message you've been circling for weeks — the rent conversation, the family letter, the complaint you owe someone, the ask you keep polishing instead of sending. Tonight it gets written with the full checklist and sent before you stand up.","task":"Write the real message, whatever it is: point first, one governing idea, a third shorter than instinct, every claim specific, and your position owned.","tips":["Run the five checks in order as you draft — point, structure, cut, specifics, position.","Read it aloud once; wherever you stumble, the reader would too.","Send it tonight — held drafts rot, and the course ends at the send button."],"focus":["structure","impact"]}
  ],
};
